INSERT INTO companies (id, nom, "nomAffichage", filiere, cre, contact, website, domain, secteur, tagline, salle, etage, description, histoire, valeurs, missions, concurrents, chiffres_cles, recrutement, questions_rh, questions_op, "logoFile", "addedLive") VALUES
(1, 'AUCHAN CHATEAUBERNARD', 'Auchan', 'COMMERCE', '', 'FOURNIER Jordan', 'https://www.auchan.fr', 'auchan.fr', 'Grande distribution alimentaire', 'Mieux manger, mieux vivre', '', '', 'Auchan est l''un des leaders de la grande distribution en France, proposant une offre complète alimentaire et non-alimentaire. L''hypermarché d''Angoulême-Châteaubernard est un acteur majeur de la consommation en Charente. Il offre des opportunités variées en alternance dans les métiers du commerce, de la logistique et du management.', 'Auchan a été fondé en 1961 par Gérard Mulliez à Roubaix. Le groupe s''est développé pour devenir l''un des plus grands distributeurs mondiaux, présent dans une douzaine de pays. En France, Auchan exploite des hypermarchés, des supermarchés et des drives, en misant sur la qualité des produits et l''innovation. Le magasin de Châteaubernard dessert la région d''Angoulême depuis plusieurs décennies et est un employeur important du territoire.', ARRAY['Confiance','Partage','Progrès','Responsabilité','Engagement client'], ARRAY['Accueillir et conseiller la clientèle en rayon','Gérer les stocks et participer aux commandes','Mettre en valeur les produits et assurer le merchandising','Participer à l''animation commerciale du magasin'], ARRAY['Carrefour','Leclerc','Intermarché','Casino','Lidl'], 'Plus de 50 000 collaborateurs en France, 13 milliards d''euros de chiffre d''affaires en France, plus de 200 hypermarchés en France', 'Auchan recherche des alternants motivés pour des BTS MCO, BUT TC ou Licence Management. Profils dynamiques, orientés client, avec un bon sens de l''organisation.', ARRAY['Pourquoi avez-vous choisi le secteur de la grande distribution pour votre alternance ?','Comment gérez-vous une situation de stress face à un afflux de clients ?','Décrivez une expérience où vous avez travaillé en équipe pour atteindre un objectif commun.','Quelle est votre approche face à un client mécontent ou difficile ?','Comment vous organisez-vous pour gérer plusieurs tâches simultanément ?'], ARRAY['Qu''est-ce que le merchandising et comment contribue-t-il aux ventes en grande surface ?','Comment analyseriez-vous les chiffres de vente d''un rayon pour identifier des axes d''amélioration ?','Que signifie la gestion des ruptures en rayon et quelles actions mettre en place ?','Quelles sont les règles d''hygiène et de sécurité alimentaire essentielles dans un hypermarché ?'], '1.png', FALSE),
(2, 'McDonald''s Grana', 'McDonald''s Grana', 'COMMERCE NS', 'Alexandra Sarikakis', 'DEGER Mélissa', 'https://www.mcdonalds.fr/', 'mcdonalds.com', 'Restauration rapide', 'Je l''adore', '', '', 'McDonald''s Grana est un restaurant franchisé du groupe McDonald''s implanté en Gironde, offrant un cadre de travail dynamique et formateur. La franchise propose des parcours en alternance pour développer des compétences en management opérationnel et en service client. C''est un environnement idéal pour acquérir une première expérience solide dans la restauration rapide.', 'McDonald''s est présent en France depuis 1979 et compte aujourd''hui plus de 1 500 restaurants. Le réseau de franchises comme Grana représente la majorité des établissements français. Ces franchisés indépendants s''engagent à respecter les standards de qualité McDonald''s tout en étant de véritables entrepreneurs locaux. L''enseigne est le premier recruteur de France et forme chaque année des milliers d''alternants.', ARRAY['Qualité','Service','Propreté','Valeur','Esprit d''équipe'], ARRAY['Accueillir et servir les clients avec le sourire','Préparer les produits en respectant les standards de qualité','Assurer la propreté et l''hygiène du restaurant','Participer à la gestion des stocks et des approvisionnements'], ARRAY['Burger King','KFC','Quick','Five Guys','Subway'], 'Plus de 1 500 restaurants en France, 70 000 collaborateurs, 1er recruteur de France, plus de 3 millions de clients par jour', 'McDonald''s recrute des alternants en BTS MCO, management des unités marchandes et bachelor restauration. Profils souriants, dynamiques, rigoureux et ayant le sens du service.', ARRAY['Pourquoi souhaitez-vous rejoindre l''univers de la restauration rapide en alternance ?','Comment réagissez-vous face à une heure de pointe avec de nombreuses commandes simultanées ?','Donnez un exemple où vous avez dû vous adapter rapidement à un changement imprévu.','Comment gérez-vous les conflits au sein d''une équipe de travail ?','Qu''est-ce que le sens du service client représente pour vous concrètement ?'], ARRAY['Quelles sont les règles HACCP essentielles à appliquer dans un restaurant de restauration rapide ?','Comment organiser la gestion des flux de clients pendant une période de pointe ?','Quels indicateurs de performance surveiller pour évaluer la qualité d''un service en restaurant ?','Comment former un nouveau membre de l''équipe aux procédures d''un restaurant McDonald''s ?'], '2.png', FALSE),
(3, 'BERGE DE GARONNE AUTO', 'Berge de Garonne Auto', 'COMMERCE NS', 'Alexandra Sarikakis', 'DIAS Sandrine', 'https://www.bergedegaronne-auto.fr', 'bgalocation.fr', 'Commerce automobile', 'Votre partenaire mobilité sur les bords de Garonne', '', '', 'Berge de Garonne Auto est un concessionnaire automobile indépendant implanté en Gironde, spécialisé dans la vente de véhicules neufs et d''occasion. La concession offre un environnement d''apprentissage complet couvrant la vente, le financement et le service après-vente. Les alternants y développent de solides compétences commerciales dans un secteur en pleine transformation.', 'Berge de Garonne Auto est une concession automobile ancrée localement sur les bords de la Garonne en Gironde. Depuis sa création, l''entreprise s''est positionnée comme un acteur de confiance pour les particuliers et professionnels de la région cherchant à acquérir un véhicule. En accompagnant ses clients de l''achat à l''entretien, la concession a construit une réputation solide sur le service et la proximité.', ARRAY['Confiance','Transparence','Service','Proximité','Expertise'], ARRAY['Accueillir et conseiller les clients dans leur projet d''achat de véhicule','Présenter et argumenter les offres de financement et d''assurance','Gérer les dossiers administratifs liés aux ventes','Assurer le suivi client et fidéliser la clientèle'], ARRAY['Renault retail','Peugeot dealers','AutoHero','Aramisauto','Lacentrale'], 'Plusieurs dizaines de véhicules en stock, service après-vente intégré, équipe commerciale expérimentée', 'Recherche des alternants en BTS NDRC ou MCO avec un intérêt pour l''automobile. Profils autonomes, à l''aise à l''oral, ayant le goût du challenge commercial.', ARRAY['Qu''est-ce qui vous attire particulièrement dans le secteur de la vente automobile ?','Comment vous y prenez-vous pour instaurer la confiance avec un client que vous rencontrez pour la première fois ?','Décrivez une situation où vous avez dû persuader quelqu''un de changer d''avis.','Comment gérez-vous un objectif de vente que vous n''avez pas atteint ?','Quelle importance accordez-vous au suivi client après une vente ?'], ARRAY['Quelles sont les étapes clés d''un entretien de vente dans le secteur automobile ?','Comment présenteriez-vous une offre de financement à un client hésitant sur son budget ?','Quels sont les documents administratifs nécessaires pour finaliser une vente de véhicule ?','Comment argumenteriez-vous la valeur d''un véhicule d''occasion face à un client qui hésite avec le neuf ?'], '3.png', FALSE),
(4, 'SAS la tradizione', 'La Tradizione', 'COMMERCE NS', 'Alexandra Sarikakis', 'De fabbio Antonio', 'https://www.latradizione.fr', 'restaurant-la-tradizione-bordeaux.fr', 'Restauration italienne', 'L''authenticité italienne au coeur de Bordeaux', '', '', 'La Tradizione est un restaurant italien authentique qui mise sur des recettes traditionnelles et des produits de qualité importés d''Italie. L''établissement bordelais propose une expérience gastronomique italienne dans un cadre chaleureux et familial. Les alternants y apprennent les fondamentaux du service en salle et de la relation client dans la restauration.', 'Fondée par Antonio De Fabbio, passionné de cuisine italienne, La Tradizione est née de la volonté de faire découvrir aux Bordelais les vraies saveurs de la cuisine transalpine. L''établissement a su fidéliser une clientèle locale grâce à l''authenticité de ses recettes familiales et à la qualité de ses produits soigneusement sélectionnés en Italie. La maison est devenue une référence de la gastronomie italienne à Bordeaux.', ARRAY['Authenticité','Qualité','Convivialité','Passion','Tradition'], ARRAY['Accueillir et installer les clients avec professionnalisme','Présenter la carte et conseiller les clients sur les plats et vins','Assurer le service en salle dans le respect des standards de l''établissement','Contribuer à la fidélisation de la clientèle par un service personnalisé'], ARRAY['Bella Italia','Vapiano','Pizza Hut','restaurants italiens locaux indépendants'], 'Restaurant à taille humaine, carte de saison renouvelée régulièrement, produits importés directement d''Italie', 'Recherche des alternants en CAP, BEP ou bac pro restauration et hôtellerie. Profils passionnés de gastronomie, souriant, rigoureux et ayant le sens de l''hospitalité.', ARRAY['Qu''est-ce qui vous a donné envie de travailler dans la restauration et l''hôtellerie ?','Comment gérez-vous une situation où plusieurs tables demandent votre attention simultanément ?','Décrivez comment vous vous comporteriez face à un client se plaignant d''un plat.','Quelle importance accordez-vous à la présentation et à l''hygiène personnelle dans votre métier ?','Comment travaillez-vous en harmonie avec la cuisine lors d''un service chargé ?'], ARRAY['Quelles sont les règles d''hygiène alimentaire (HACCP) à respecter en salle et en cuisine ?','Comment construire un argumentaire de vente autour d''un plat du jour ou d''un vin ?','Quelles techniques utilisez-vous pour mémoriser une grande carte de restaurant ?','Comment gérer une erreur de commande sans perturber l''ambiance de la table ?'], '4.png', FALSE),
(5, 'Mc Donald''s', 'McDonald''s', 'COMMERCE NS', 'Alexandra Sarikakis', 'EL AIDI Dalila', 'https://www.mcdonalds.fr/', 'mcdonalds.com', 'Restauration rapide', 'Je l''adore', '', '', 'McDonald''s est le leader mondial de la restauration rapide, présent dans plus de 100 pays avec plus de 40 000 restaurants. En France, l''enseigne s''est imposée comme le premier recruteur national et forme chaque année des milliers d''alternants. Rejoindre McDonald''s en alternance, c''est intégrer un groupe structuré offrant de réelles perspectives d''évolution.', 'McDonald''s a été fondé aux États-Unis en 1940 par les frères McDonald avant d''être développé par Ray Kroc à partir de 1954. Arrivé en France en 1979, le groupe a connu une croissance continue pour atteindre plus de 1 500 restaurants. L''enseigne a profondément adapté son offre aux goûts français, en proposant des produits locaux et en s''engageant dans une démarche RSE ambitieuse, notamment sur la qualité des ingrédients et le développement durable.', ARRAY['Qualité','Service','Propreté','Valeur','Inclusion'], ARRAY['Assurer l''accueil et le service client au comptoir et en salle','Participer à la préparation des produits selon les standards qualité','Gérer l''encaissement et les outils numériques de commande','Contribuer au management d''équipe et à la formation des équipiers'], ARRAY['Burger King','KFC','Quick','Five Guys','Subway'], 'Plus de 1 500 restaurants en France, 70 000 salariés, 3 millions de clients par jour en France, 1er recruteur privé de France', 'McDonald''s recrute des alternants pour des BTS MCO, management ou bachelor restauration. Profils dynamiques, rigoureux, avec le sens du service et l''esprit d''équipe.', ARRAY['Pourquoi avez-vous choisi McDonald''s pour votre alternance parmi tous les acteurs de la restauration ?','Comment définissez-vous la qualité de service dans un environnement de restauration rapide ?','Parlez-moi d''une situation où vous avez pris une initiative pour améliorer le quotidien d''une équipe.','Comment gérez-vous la pression lors des pics d''activité en restauration ?','Quelles qualités pensez-vous indispensables pour évoluer vers un poste de manager chez McDonald''s ?'], ARRAY['Quelles normes HACCP sont essentielles dans la restauration rapide et comment les appliquez-vous ?','Comment organiser efficacement la rotation des postes dans une équipe de restauration ?','Quels KPI un manager de restaurant doit-il surveiller au quotidien ?','Comment gérer un conflit entre deux membres de l''équipe en plein service ?'], '5.png', FALSE),
(6, 'BOULANGERIES ANGE', 'Boulangeries Ange', 'COMMERCE', 'Alexandra Sarikakis', 'MOINDROT LAURENT', 'https://www.boulangerie-ange.fr/', 'boulangerie-ange.fr', 'Boulangerie-pâtisserie artisanale en réseau', 'Le goût du fait maison, à toute heure', '', '', 'Boulangeries Ange est le premier réseau de boulangeries artisanales en franchise en France, combinant la tradition du fait maison avec les avantages d''un réseau structuré. Chaque boulangerie Ange fabrique ses produits sur place, du pain aux viennoiseries en passant par la pâtisserie et la restauration rapide. Les alternants y découvrent un métier complet mêlant production artisanale et commerce de proximité.', 'Boulangeries Ange a été fondée en 2009 avec l''ambition de démocratiser la boulangerie artisanale de qualité en franchise. Depuis, le réseau s''est développé pour compter plus de 250 boutiques en France et à l''international. L''enseigne se distingue par son engagement sur la fabrication maison, le respect du savoir-faire artisan et une offre variée qui s''étend du petit-déjeuner au déjeuner. Ange est aujourd''hui un acteur incontournable de la boulangerie moderne.', ARRAY['Artisanat','Fraîcheur','Générosité','Proximité','Innovation'], ARRAY['Vendre et conseiller les clients sur les produits de boulangerie et pâtisserie','Assurer la mise en rayon et la présentation des produits','Gérer les encaissements et fidéliser la clientèle','Participer à la production selon les recettes de l''enseigne'], ARRAY['Paul','Maison Landemaine','Brioche Dorée','boulangeries artisanales locales','Feuillette'], 'Plus de 250 boutiques en France et à l''international, fabrication 100% maison, ouverture 7j/7 dès 6h du matin', 'Ange recrute des alternants en CAP vente, BTS MCO ou commerce. Profils passionnés par les produits alimentaires, avec le sens du contact et de la présentation.', ARRAY['Qu''est-ce qui vous attire dans le commerce de proximité et la boulangerie artisanale ?','Comment gérez-vous une file d''attente longue en caisse avec des clients impatients ?','Décrivez une expérience où votre sens du service a fidélisé un client.','Comment vous adaptez-vous aux horaires décalés (ouverture à 6h) propres aux métiers de la boulangerie ?','Quelle place donnez-vous à la présentation des produits dans l''acte de vente ?'], ARRAY['Comment argumenter la valeur d''un produit artisanal face à la concurrence industrielle ?','Quelles règles d''hygiène sont à respecter dans un espace de vente alimentaire ?','Comment gérer la gestion des invendus en fin de journée pour limiter le gaspillage ?','Quelles techniques de merchandising appliquer en boulangerie pour augmenter le panier moyen ?'], '6.png', FALSE),
(7, 'Columbus Café & Co', 'Columbus Café & Co', 'COMMERCE NS', 'Alexandra Sarikakis', 'GUYAU AURELIE', 'https://www.columbuscafe.com/', '7_columbus.png', 'Restauration / Cafés & snacking', 'Le café qui vous ressemble', '', '', 'Columbus Café & Co est une chaîne française de cafés spécialisée dans les boissons chaudes et le snacking de qualité. Avec plus de 250 points de vente en France, l''enseigne propose une expérience de restauration rapide centrée sur la convivialité et l''authenticité. Les alternants y développent des compétences solides en relation client, gestion de point de vente et commerce.', 'Fondée en 1994, Columbus Café & Co s''est imposée comme une référence dans le secteur des coffee shops à la française. L''enseigne se distingue par son ancrage local et son modèle de franchise qui valorise l''entrepreneuriat. Avec son ours emblématique, Columbus Café incarne une approche chaleureuse et accessible de la restauration.', ARRAY['Convivialité','Qualité','Esprit d''équipe','Authenticité','Engagement'], ARRAY['Accueillir et conseiller les clients sur les produits','Préparer et servir boissons et snacking dans le respect des standards','Assurer la tenue et la propreté du point de vente','Contribuer au développement du chiffre d''affaires'], ARRAY['Starbucks','Paul','Prêt à Manger','Café de Flore'], 'Plus de 250 points de vente en France, réseau en franchise, présent depuis 1994', 'Columbus Café & Co recherche des alternants en BTS MCO ou MUM. Profils dynamiques, orientés service client, avec un goût pour la restauration et le contact humain.', ARRAY['Qu''est-ce qui vous attire dans l''univers de la restauration rapide et des cafés ?','Comment gérez-vous une situation stressante en période de forte affluence ?','Parlez-moi d''une expérience où vous avez contribué à satisfaire un client difficile.','Pourquoi choisir Columbus Café & Co plutôt qu''un autre réseau de restauration ?','Comment travaillez-vous en équipe pour atteindre des objectifs collectifs ?'], ARRAY['Quelles sont les règles d''hygiène et de sécurité alimentaire à respecter en restauration ?','Comment gérez-vous la rotation des stocks et la gestion des invendus ?','Quelles techniques utilisez-vous pour augmenter le ticket moyen d''un client ?','Comment assurez-vous la qualité constante des produits servis tout au long de la journée ?'], NULL, FALSE),
(8, 'Pause gourmande', 'Pause Gourmande', 'COMMERCE NS', 'Alexandra Sarikakis', 'Nicaise Alexandra', 'https://www.pause-gourmande.fr', '', 'Restauration et vente de produits gourmands', 'Une pause savoureuse à chaque instant', '', '', 'Pause Gourmande est un établissement de restauration proposant une offre de snacking, sandwichs et produits sucrés-salés de qualité pour les pauses déjeuner et les moments de convivialité. L''entreprise mise sur la fraîcheur des produits et un accueil chaleureux pour fidéliser sa clientèle locale. Les alternants y acquièrent une expérience précieuse en vente alimentaire et en relation client.', 'Pause Gourmande a été fondée par Alexandra Nicaise avec la passion de proposer une restauration rapide mais de qualité. L''enseigne s''est développée en privilégiant les produits frais, les recettes maison et le service souriant. La clientèle fidèle témoigne du succès d''un concept qui allie gourmandise, rapidité et accessibilité au quotidien.', ARRAY['Fraîcheur','Gourmandise','Convivialité','Qualité','Simplicité'], ARRAY['Préparer et présenter les produits de vente','Accueillir et servir les clients avec le sourire','Gérer la caisse et les encaissements','Assurer l''hygiène et la propreté de l''espace de vente'], ARRAY['Boulangeries artisanales locales','Snacks indépendants','Sandwicheries'], 'Commerce de proximité, fort ancrage local, clientèle fidèle et régulière', 'Recherche des alternants en CAP vente ou BTS commerce. Profils aimant le contact client, avec un intérêt pour les produits alimentaires et la restauration.', ARRAY['Qu''est-ce qui vous plaît dans le contact quotidien avec une clientèle de proximité ?','Comment gérez-vous un afflux important de clients à l''heure du déjeuner ?','Décrivez comment vous réagiriez face à un client insatisfait de sa commande.','Quelles sont selon vous les qualités essentielles pour travailler en vente alimentaire ?','Comment vous assurez-vous du respect des règles d''hygiène au quotidien ?'], ARRAY['Quelles sont les règles d''hygiène alimentaire à appliquer dans un espace de vente de produits frais ?','Comment assurer la rotation des produits et éviter le gaspillage alimentaire ?','Quelles techniques utilisez-vous pour inciter un client à augmenter son panier moyen ?','Comment gérer les ruptures de stock lors des périodes de forte affluence ?'], NULL, FALSE),
(9, 'Milano Pizza', 'Milano Pizza', 'COMMERCE NS', 'Alexandra Sarikakis', 'tayeb dhaou', 'https://www.milanobordeaux.fr', '', 'Restauration pizzeria', 'La pizza authentique à l''italienne à Bordeaux', '', '', 'Milano Pizza est une pizzeria bordelaise proposant des pizzas artisanales cuites au four à bois, élaborées avec des ingrédients frais et des recettes inspirées de la tradition italienne. L''établissement accueille des alternants souhaitant découvrir les métiers de la restauration dans un cadre convivial et familial. C''est une belle opportunité de se former à la vente et au service en restauration.', 'Milano Pizza a été créée à Bordeaux avec la passion de proposer une pizza de qualité, proche de la tradition napolitaine. L''établissement a su trouver son public grâce à des produits authentiques, une pâte maison travaillée avec soin et un accueil généreux. Au fil des années, Milano Pizza est devenue une adresse de référence pour les amateurs de pizza à Bordeaux.', ARRAY['Authenticité','Passion','Fraîcheur','Convivialité','Savoir-faire'], ARRAY['Accueillir les clients et prendre les commandes','Préparer les pizzas selon les recettes de la maison','Gérer les livraisons et le service à emporter','Assurer la propreté et l''hygiène de l''établissement'], ARRAY['Pizza del Arte','Domino''s Pizza','Papa John''s','pizzerias artisanales locales'], 'Pizzeria à taille humaine, cuisson au four à bois, ingrédients frais sélectionnés, service sur place et à emporter', 'Recherche des alternants en CAP ou BTS restauration, commerce ou vente. Profils motivés, ayant le sens du service et une curiosité pour la gastronomie italienne.', ARRAY['Pourquoi avez-vous choisi la restauration pour débuter votre parcours professionnel ?','Comment vous adaptez-vous à un environnement de travail rapide et physiquement exigeant ?','Donnez un exemple de situation où vous avez fait preuve de débrouillardise.','Comment gérez-vous la relation avec un client qui se plaint du temps d''attente ?','Qu''est-ce que le travail en équipe signifie concrètement pour vous ?'], ARRAY['Quelles sont les règles d''hygiène essentielles à respecter dans une cuisine de pizzeria ?','Comment organiser les postes de travail pour optimiser le flux de production d''une pizzeria ?','Quelles techniques de vente additive peut-on appliquer dans une pizzeria (boissons, desserts) ?','Comment gérer la gestion des stocks d''ingrédients frais pour éviter les pertes ?'], '9.svg', FALSE),
(10, 'GROUPE MONDIAL MENUISERIES', 'Groupe Mondial Menuiseries', 'COMMERCE NS', 'Alexandra Sarikakis', 'TISSOT Olivier', 'https://www.groupe-mondial.fr', 'mondialmenuiseries.fr', 'Menuiseries et fermetures', 'Des solutions menuiseries sur mesure pour votre habitat', '', '', 'Le Groupe Mondial Menuiseries est spécialisé dans la vente et la pose de menuiseries extérieures (fenêtres, volets, portes, portails) auprès des particuliers et professionnels. L''entreprise accompagne ses clients de la conception à l''installation, en proposant des solutions adaptées à chaque projet. Les alternants y développent des compétences en vente de solutions techniques et en conseil à domicile.', 'Le Groupe Mondial Menuiseries s''est construit autour d''un savoir-faire dans les fermetures et menuiseries extérieures, répondant à la demande croissante de rénovation thermique des logements. En s''appuyant sur une force commerciale expérimentée et des produits de qualité, le groupe a développé son implantation régionale. L''entreprise accompagne aujourd''hui de nombreux particuliers dans l''amélioration de leur habitat.', ARRAY['Qualité','Conseil','Proximité','Professionnalisme','Satisfaction client'], ARRAY['Prospecter et conseiller les particuliers sur leurs projets de menuiserie','Réaliser des visites à domicile et établir des devis personnalisés','Assurer le suivi des dossiers clients de la commande à la pose','Développer et fidéliser un portefeuille clients en région'], ARRAY['Tryba','K•Line','Lapeyre','Dépannage habitat','Solabaie'], 'Présence régionale, pose incluse, gamme complète de fenêtres et fermetures, financement possible', 'Recherche des alternants en BTS NDRC ou technico-commercial. Profils à l''aise en prospection, avec le goût du terrain et une sensibilité aux produits techniques.', ARRAY['Qu''est-ce qui vous attire dans la vente de produits techniques auprès des particuliers ?','Comment abordez-vous un rendez-vous de prospection chez un particulier que vous ne connaissez pas ?','Décrivez une situation où vous avez réussi à convaincre quelqu''un d''un projet qu''il hésitait à lancer.','Comment gérez-vous un client qui vous demande un délai de réflexion prolongé ?','Que signifie pour vous le service après-vente dans une relation commerciale durable ?'], ARRAY['Quels sont les principaux critères techniques à connaître pour conseiller un client sur ses fenêtres ?','Comment construire un devis adapté au budget et aux besoins d''un particulier ?','Quelles aides financières à la rénovation énergétique pouvez-vous mentionner à vos clients ?','Comment gérer un client mécontent suite à un retard de pose ou un défaut de produit ?'], '10.png', FALSE),
(11, 'NETCO', 'Netco', 'COMMERCE NS', 'Alexandra Sarikakis', 'ZACCHI GWENDOLINE', 'https://www.netco.fr', 'netco.fr', 'Services informatiques et numériques', 'Vos projets numériques entre de bonnes mains', '', '', 'Netco est une entreprise de services du numérique (ESN) proposant des solutions informatiques aux entreprises de toutes tailles. Elle intervient sur des projets variés alliant infrastructure, développement et conseil digital. Les alternants y trouvent un terrain d''apprentissage idéal pour combiner compétences commerciales et sensibilité aux technologies.', 'Netco a été fondée pour répondre aux besoins croissants des entreprises en matière de transformation numérique. La société s''est progressivement imposée comme un partenaire de confiance pour ses clients en proposant des services sur mesure, de l''audit à la mise en oeuvre de solutions IT. Présente en région, Netco continue de se développer en s''appuyant sur des équipes pluridisciplinaires et des alternants qu''elle forme avec exigence.', ARRAY['Innovation','Réactivité','Expertise','Partenariat','Agilité'], ARRAY['Participer au développement commercial de l''activité','Accompagner les clients dans leurs projets de transformation numérique','Assurer le suivi des propositions commerciales et des contrats','Contribuer aux actions marketing et communication de l''entreprise'], ARRAY['Capgemini','Sopra Steria','Atos','ESN régionales','Devoteam'], 'ESN régionale en croissance, large portefeuille clients PME/ETI, équipes techniques certifiées', 'Netco recherche des alternants en BTS NDRC, bachelor commercial ou marketing digital avec une sensibilité au monde du numérique.', ARRAY['Pourquoi avez-vous choisi de vous orienter vers le commerce dans le secteur du numérique ?','Comment expliquez-vous un concept technique complexe à un client non spécialiste ?','Décrivez une situation où vous avez dû faire preuve de persévérance pour atteindre un objectif.','Comment vous tenez-vous informé des évolutions technologiques et numériques ?','Quelle est votre approche pour construire une relation de confiance avec un client B2B ?'], ARRAY['Quelles sont les principales offres de services d''une ESN et comment les différencier ?','Comment préparer et mener un rendez-vous de découverte chez un prospect B2B ?','Qu''est-ce qu''un appel d''offres IT et comment y répondre efficacement ?','Quels outils digitaux utilisez-vous pour prospecter et qualifier des leads ?'], '11.svg', FALSE),
(12, 'DERICHEBOURG INTERIM & RECRUTEMENT', 'Derichebourg Intérim', 'RH / TOURISME', 'Annick', 'BEYLARD SEBASTIEN', 'https://www.derichebourg-interim.com', 'derichebourg.com', 'Travail temporaire et recrutement', 'Le travail, c''est notre métier', '', '', 'Derichebourg Intérim & Recrutement est une agence de travail temporaire et de recrutement appartenant au groupe Derichebourg, acteur multisectoriel de premier plan. Elle accompagne entreprises et candidats dans la gestion des ressources humaines avec une approche à la fois réactive et humaine. Les alternants y découvrent les métiers du recrutement, de la gestion administrative RH et du développement commercial.', 'Le groupe Derichebourg, fondé dans les années 1950, s''est diversifié dans de nombreux secteurs dont les services aux entreprises, l''environnement et le travail temporaire. Sa branche intérim et recrutement s''est développée pour répondre à la demande croissante des entreprises en flexibilité de main-d''oeuvre. Avec un réseau d''agences nationales, Derichebourg Intérim est aujourd''hui reconnu pour son expertise sectorielle et son accompagnement personnalisé des candidats.', ARRAY['Humanisme','Réactivité','Proximité','Expertise','Engagement'], ARRAY['Sourcer et présélectionner des candidats pour les entreprises clientes','Gérer les contrats de travail temporaire et le suivi administratif','Développer le portefeuille clients de l''agence par la prospection','Accompagner les candidats dans leur parcours professionnel'], ARRAY['Adecco','Manpower','Randstad','Synergie','Proman'], 'Groupe présent dans 12 pays, plus de 700 agences en France, des milliers d''intérimaires placés chaque jour', 'Derichebourg recherche des alternants en Licence RH, bachelor commerce ou gestion. Profils à l''aise avec le relationnel, organisés et aimant le travail en équipe.', ARRAY['Qu''est-ce qui vous attire dans les métiers des ressources humaines et du recrutement ?','Comment gérez-vous plusieurs dossiers de candidats en même temps avec des délais serrés ?','Décrivez une situation où vous avez dû faire preuve d''empathie pour aider quelqu''un.','Comment conciliez-vous les attentes parfois contradictoires des candidats et des entreprises clientes ?','Quelle importance accordez-vous à la confidentialité dans le métier du recrutement ?'], ARRAY['Quelles sont les étapes d''un processus de recrutement complet, de la définition du besoin à l''intégration ?','Comment rédiger une offre d''emploi attractive pour attirer les bons candidats ?','Quelles techniques d''entretien utilisez-vous pour évaluer les compétences d''un candidat ?','Quelles obligations légales encadrent le recours au travail temporaire en France ?'], '12.png', FALSE),
(13, 'CITYZ MEDIA', 'Cityz Media', 'RH / TOURISME', 'Annick', 'CLEMENT Christophe', 'https://www.cityzmedia.fr', 'cityzmedia.fr', 'Communication et médias urbains', 'La communication locale au coeur de la ville', '', '', 'Cityz Media est une agence spécialisée dans la communication locale et les médias urbains, proposant des solutions publicitaires et d''affichage pour les acteurs économiques et institutionnels. Elle accompagne ses clients dans la conception et la diffusion de campagnes de communication ciblées sur les territoires. Les alternants y développent des compétences en vente de solutions publicitaires et en gestion de projets communication.', 'Cityz Media s''est positionnée comme un acteur innovant de la communication locale en développant des supports d''affichage urbain et des solutions numériques adaptées aux besoins des annonceurs locaux. L''agence a su construire une offre complète alliant conseil, création et diffusion, en répondant aux enjeux de visibilité des entreprises sur leur territoire. Ses équipes pluridisciplinaires accompagnent des clients variés de l''artisan à la grande collectivité.', ARRAY['Créativité','Proximité','Innovation','Efficacité','Engagement'], ARRAY['Prospecter et fidéliser des annonceurs locaux','Conseiller les clients sur les supports et stratégies de communication','Gérer les campagnes publicitaires de A à Z','Analyser les performances des campagnes et proposer des améliorations'], ARRAY['JCDecaux','Clear Channel','agences de communication locales','régies publicitaires locales'], 'Agence en développement, présence sur plusieurs territoires, portfolio clients diversifié PME et collectivités', 'Cityz Media recherche des alternants en BTS communication, marketing ou bachelor marketing/communication. Profils créatifs, à l''aise à l''oral et passionnés par les médias.', ARRAY['Qu''est-ce qui vous passionne dans la communication et les médias locaux ?','Comment vous assurez-vous que vos messages publicitaires sont bien adaptés à une cible locale ?','Décrivez un projet créatif dont vous êtes fier et expliquez votre démarche.','Comment gérez-vous un client qui n''est pas satisfait des résultats d''une campagne ?','Comment restez-vous informé des tendances en communication et publicité ?'], ARRAY['Quels sont les différents formats de publicité extérieure et leurs avantages respectifs ?','Comment mesurer l''efficacité d''une campagne de communication locale ?','Comment construire un plan média adapté au budget et aux objectifs d''un annonceur local ?','Quels outils digitaux utilisez-vous pour concevoir et gérer des supports de communication ?'], '13.png', FALSE),
(14, 'Guy Hoquet L''Agence Signature', 'Guy Hoquet Signature', 'IMMOBILIER', 'Arnaud BAUDUIN', 'DUPUIS Giulia & Franck', 'https://www.guy-hoquet.com', 'guy-hoquet.com', 'Immobilier résidentiel', 'L''immobilier autrement', '', '', 'Guy Hoquet est l''un des réseaux immobiliers leaders en France, avec plus de 500 agences. L''agence Signature propose une approche haut de gamme de la transaction immobilière résidentielle sur le marché bordelais. Les alternants y découvrent les métiers de la négociation immobilière, de l''estimation à la signature, dans un cadre structuré et formateur.', 'Guy Hoquet l''Immobilier a été fondé en 1994 avec la volonté de réinventer le métier d''agent immobilier en proposant un service premium et transparent. Le réseau a connu une croissance rapide pour devenir l''un des réseaux les plus reconnus en France, comptant plus de 500 agences. L''agence Signature à Bordeaux incarne cette ambition avec une approche différenciante sur un marché immobilier dynamique.', ARRAY['Excellence','Transparence','Innovation','Proximité','Engagement'], ARRAY['Prospecter et rentrer des mandats de vente ou de location','Accompagner les clients acheteurs dans leur recherche de bien','Réaliser des estimations et des visites de biens','Gérer les négociations et le suivi administratif des transactions'], ARRAY['Orpi','Century 21','Laforêt','IAD','Foncia Transaction'], 'Plus de 500 agences en France, plus de 3 000 collaborateurs, leader sur plusieurs marchés régionaux', 'Guy Hoquet recherche des alternants en BTS PI (Professions Immobilières) ou bachelor immobilier. Profils dynamiques, ambitieux, avec le goût du terrain et du challenge.', ARRAY['Pourquoi avez-vous choisi l''immobilier et le réseau Guy Hoquet pour votre alternance ?','Comment gérez-vous la relation avec un vendeur dont les attentes de prix sont trop élevées par rapport au marché ?','Décrivez une situation où vous avez dû convaincre quelqu''un de vous faire confiance.','Comment vous organisez-vous pour gérer simultanément plusieurs mandats et clients ?','Qu''est-ce que la déontologie professionnelle signifie pour vous dans l''immobilier ?'], ARRAY['Quelles sont les étapes légales d''une transaction immobilière de la promesse à l''acte authentique ?','Comment réaliser une estimation de bien immobilier par la méthode comparative ?','Quels sont les diagnostics obligatoires à fournir lors de la vente d''un bien immobilier ?','Comment prospecter efficacement pour rentrer de nouveaux mandats dans un secteur géographique défini ?'], '14.png', FALSE),
(15, '2E GESTION', '2E Gestion', 'IMMOBILIER', 'Arnaud BAUDUIN', 'GAUTRIN ELISE', 'https://www.2egestion.fr', '2e-gestion.fr', 'Gestion locative et syndic', 'Votre patrimoine géré avec expertise et bienveillance', '', '', '2E Gestion est un cabinet immobilier spécialisé dans la gestion locative et la gestion de copropriétés (syndic) en Gironde. Il accompagne propriétaires bailleurs et copropriétaires dans la gestion quotidienne de leurs biens immobiliers. Les alternants y développent des compétences pointues en droit immobilier, comptabilité et relation client.', '2E Gestion a été créé pour apporter aux propriétaires une gestion rigoureuse et humaine de leur patrimoine immobilier. Le cabinet s''est spécialisé dans la gestion locative et le syndic de copropriété en développant une approche personnalisée et transparente. Ancré localement, 2E Gestion est devenu un partenaire de confiance pour de nombreux propriétaires girondins soucieux de valoriser leur patrimoine.', ARRAY['Rigueur','Transparence','Proximité','Confiance','Expertise'], ARRAY['Gérer les dossiers locataires (entrée, sortie, loyers, contentieux)','Assurer la gestion des copropriétés (AG, travaux, charges)','Conseiller les propriétaires sur la gestion de leur patrimoine','Traiter les demandes et réclamations des locataires et copropriétaires'], ARRAY['Foncia','Nexity Gestion','BNP Paribas Real Estate','cabinets locaux de gestion'], 'Cabinet à taille humaine, portefeuille de biens gérés en Gironde, double expertise gestion locative et syndic', '2E Gestion recherche des alternants en BTS PI ou bachelor immobilier. Profils rigoureux, organisés, avec un intérêt pour le droit et la gestion patrimoniale.', ARRAY['Qu''est-ce qui vous a orienté vers la gestion immobilière plutôt que la transaction ?','Comment gérez-vous un conflit entre un propriétaire et son locataire ?','Décrivez votre méthode pour rester organisé face à de nombreux dossiers simultanés.','Quelle est votre réaction face à une situation juridique complexe que vous ne maîtrisez pas ?','Comment expliquez-vous clairement des charges de copropriété à un copropriétaire non spécialiste ?'], ARRAY['Quelles sont les obligations du gestionnaire locatif vis-à-vis du propriétaire bailleur ?','Quelles sont les étapes d''une assemblée générale de copropriété ?','Comment gérer une procédure d''impayé de loyer en respectant les délais légaux ?','Qu''est-ce que l''état des lieux et quels sont ses enjeux juridiques ?'], '15.png', FALSE),
(16, 'MINJOT IMMOBILIER', 'Minjot Immobilier', 'IMMOBILIER', 'Arnaud BAUDUIN', 'MINJOT Florian', 'https://www.minjot-immobilier.fr', 'eraimmo.fr', 'Transaction immobilière', 'L''immobilier de confiance, à votre service', '', '', 'Minjot Immobilier est une agence indépendante spécialisée dans la transaction immobilière résidentielle en Gironde. Dirigée par Florian Minjot, elle propose un accompagnement personnalisé aux acheteurs et vendeurs tout au long de leur projet immobilier. Les alternants y bénéficient d''une formation de terrain au métier de négociateur immobilier.', 'Minjot Immobilier a été fondée par Florian Minjot avec la conviction que la transaction immobilière doit se faire dans la transparence et la confiance. L''agence indépendante s''est distinguée sur le marché bordelais par son accompagnement personnalisé et sa connaissance fine du territoire. En privilégiant la qualité de service sur le volume, Minjot Immobilier a construit une réputation solide auprès de sa clientèle locale.', ARRAY['Confiance','Intégrité','Proximité','Professionnalisme','Persévérance'], ARRAY['Prospecter des mandats de vente sur le secteur géographique de l''agence','Accompagner les clients acquéreurs de la recherche à la signature','Réaliser des estimations et organiser des visites','Assurer le suivi administratif des dossiers de vente'], ARRAY['Agences immobilières indépendantes locales','IAD','SquareHabitat','agences de réseaux nationaux'], 'Agence indépendante à taille humaine, expertise locale forte, accompagnement personnalisé de chaque client', 'Minjot Immobilier recherche des alternants en BTS PI ou licence immobilier. Profils autonomes, ambitieux et passionnés par l''immobilier et le contact humain.', ARRAY['Qu''est-ce qui vous a attiré vers l''immobilier comme secteur professionnel ?','Comment vous démarqueriez-vous d''un réseau national pour convaincre un vendeur de vous confier son bien ?','Décrivez votre méthode pour rester motivé face aux refus de mandats lors de la prospection.','Comment gérez-vous la relation entre un vendeur et un acheteur aux intérêts divergents ?','Quelle importance accordez-vous à la connaissance du territoire dans le métier d''agent immobilier ?'], ARRAY['Quelles sont les différences entre un mandat simple et un mandat exclusif en immobilier ?','Comment préparez-vous une visite de bien pour maximiser les chances de coup de coeur ?','Quelles informations devez-vous vérifier avant de prendre un mandat de vente ?','Comment négocier efficacement entre les parties pour conclure une vente dans les meilleures conditions ?'], '16.svg', FALSE),
(17, 'CDC HABITAT', 'CDC Habitat', 'IMMOBILIER', 'Arnaud BAUDUIN', 'PARMENTIER Nadia', 'https://www.cdchabitat.fr', 'cdchabitat.fr', 'Logement social et intermédiaire', 'Construire ensemble un habitat pour tous', '', '', 'CDC Habitat est le premier groupe de logement en France, filiale de la Caisse des Dépôts. Il gère plus de 550 000 logements sociaux et intermédiaires sur l''ensemble du territoire national. Les alternants y découvrent les enjeux du logement accessible, de la gestion locative sociale et du développement de nouveaux programmes immobiliers.', 'CDC Habitat est né de la fusion de plusieurs filiales immobilières de la Caisse des Dépôts, avec pour mission de développer une offre de logements accessibles sur tout le territoire. Le groupe accompagne les collectivités territoriales dans la construction et la réhabilitation de logements sociaux et intermédiaires. Engagé dans la transition énergétique, CDC Habitat investit massivement dans la rénovation de son parc pour réduire son empreinte carbone.', ARRAY['Solidarité','Engagement','Durabilité','Innovation','Mixité sociale'], ARRAY['Gérer la relation avec les locataires (entrées, sorties, réclamations)','Commercialiser les logements intermédiaires auprès des candidats','Participer aux projets de construction et de réhabilitation','Contribuer au développement de partenariats avec les collectivités'], ARRAY['Action Logement','bailleurs sociaux régionaux','Habitat en Région','In''li'], 'Plus de 550 000 logements gérés en France, 1er groupe de logement, filiale Caisse des Dépôts, 4 000 collaborateurs', 'CDC Habitat recrute des alternants en BTS PI, bachelor immobilier ou licence professionnelle. Profils sensibles aux enjeux sociaux, rigoureux et organisés.', ARRAY['Pourquoi vous intéressez-vous au logement social et aux missions de service public ?','Comment gérez-vous une situation où un locataire en difficulté ne peut plus payer son loyer ?','Décrivez votre vision du service rendu à des publics en situation de vulnérabilité.','Comment conciliez-vous les obligations légales du bailleur et l''accompagnement humain du locataire ?','Quelle place accordez-vous au développement durable dans la gestion d''un patrimoine immobilier ?'], ARRAY['Quelles sont les spécificités du logement social par rapport au logement privé (attributions, plafonds de ressources) ?','Quelles sont les étapes d''attribution d''un logement social via la commission d''attribution ?','Quels sont les droits et obligations d''un locataire du parc social ?','Comment la réglementation thermique impacte-t-elle la gestion d''un parc de logements ?'], '17.svg', FALSE),
(18, 'Human Immobilier', 'Human Immobilier', 'IMMOBILIER', 'Arnaud BAUDUIN', 'PETIT Morgane', 'https://www.human-immobilier.fr', 'human-immobilier.fr', 'Transaction immobilière', 'L''immobilier avec le coeur', '', '', 'Human Immobilier est un réseau d''agences immobilières indépendantes qui place l''humain au centre de chaque transaction. Le réseau valorise des pratiques éthiques et transparentes, en reversant une partie de ses honoraires à des associations. Les alternants y apprennent un métier de négociateur immobilier avec des valeurs fortes et une approche différenciante.', 'Human Immobilier a été fondé avec la conviction que l''immobilier peut et doit être exercé différemment, en plaçant l''humain et la transparence avant tout. Le réseau s''est développé en rassemblant des agences partageant les mêmes valeurs éthiques et solidaires. Sa politique de reversement d''une partie des honoraires à des associations en fait un acteur immobilier engagé et socialement responsable.', ARRAY['Humanisme','Transparence','Éthique','Solidarité','Engagement'], ARRAY['Prospecter et accompagner les clients dans leurs projets immobiliers','Réaliser des estimations de biens et organiser des visites','Gérer les négociations avec professionnalisme et éthique','Assurer le suivi administratif des dossiers jusqu''à la signature'], ARRAY['Orpi','Guy Hoquet','Century 21','Laforêt','IAD'], 'Réseau d''agences indépendantes partageant des valeurs communes, reversement d''une partie des honoraires à des associations', 'Human Immobilier recherche des alternants en BTS PI ou bachelor immobilier. Profils sensibles aux valeurs humaines et éthiques, avec un sens aigu du contact et de l''écoute.', ARRAY['Qu''est-ce qui vous a séduit dans l''approche humaine et éthique de Human Immobilier ?','Comment conciliez-vous performance commerciale et valeurs éthiques dans le métier de négociateur ?','Décrivez une situation où vous avez fait passer les intérêts de quelqu''un avant les vôtres.','Comment gérez-vous une situation où un client vous pousse à prendre des raccourcis déontologiques ?','Quelle importance accordez-vous à la RSE dans votre choix d''employeur ?'], ARRAY['Quelles sont les obligations déontologiques d''un agent immobilier selon la loi Hoguet ?','Comment expliquer de manière transparente les honoraires d''agence à un vendeur ou acquéreur ?','Quelles sont les étapes clés pour sécuriser juridiquement une transaction immobilière ?','Comment utiliser les outils digitaux (visite virtuelle, signature électronique) pour améliorer l''expérience client ?'], '18.png', FALSE),
(19, 'AMI', 'AMI Immobilier', 'IMMOBILIER', 'Arnaud BAUDUIN', 'POUGET YVES', 'https://www.ami-immobilier.fr', 'ami-agence.fr', 'Transaction et gestion immobilière', 'Votre projet immobilier, notre priorité', '', '', 'AMI est une agence immobilière indépendante proposant des services complets de transaction et de gestion locative en Gironde. Elle accompagne acquéreurs, vendeurs et propriétaires bailleurs avec un service personnalisé et réactif. Les alternants y découvrent les deux facettes du métier immobilier : la vente et la gestion.', 'AMI Immobilier a été fondée avec l''ambition de proposer un service immobilier complet et de qualité aux particuliers de la région girondine. L''agence a développé une double expertise en transaction et en gestion locative, permettant à ses clients de bénéficier d''un accompagnement global. En cultivant la proximité et la réactivité, AMI s''est construit une réputation solide sur son territoire.', ARRAY['Proximité','Réactivité','Expertise','Confiance','Service'], ARRAY['Rentrer et gérer des mandats de vente et de location','Accompagner les clients dans leurs projets d''achat ou de location','Gérer les biens immobiliers en portefeuille','Développer la notoriété de l''agence sur son secteur'], ARRAY['Agences locales indépendantes','Foncia','Nexity','Century 21','Orpi'], 'Agence à taille humaine, double compétence transaction et gestion, ancrage local fort en Gironde', 'AMI recherche des alternants en BTS PI ou bachelor immobilier. Profils dynamiques, autonomes, avec le sens des responsabilités.', ARRAY['Pourquoi souhaitez-vous apprendre le métier de l''immobilier dans une agence indépendante ?','Comment gérez-vous votre emploi du temps entre des visites, des rendez-vous bailleurs et des dossiers administratifs ?','Décrivez une situation où vous avez dû gérer simultanément plusieurs priorités différentes.','Comment réagissez-vous lorsqu''une vente que vous pensiez conclue tombe à l''eau ?','Quelle est votre conception du service client dans l''immobilier ?'], ARRAY['Quelle est la différence entre la gestion locative nue et la gestion locative meublée ?','Comment calculer la rentabilité locative d''un bien immobilier pour un investisseur ?','Quelles sont les obligations du propriétaire bailleur en matière d''entretien du logement ?','Comment gérer une procédure d''expulsion locative dans le respect des délais légaux ?'], '19.png', FALSE),
(20, 'Domofrance', 'Domofrance', 'IMMOBILIER', 'Arnaud BAUDUIN', 'VIDAL Laetitia', 'https://www.domofrance.fr', 'domofrance.fr', 'Logement social', 'Bâtir des logements, construire des vies', '', '', 'Domofrance est l''un des principaux bailleurs sociaux de la région Nouvelle-Aquitaine, gérant plus de 30 000 logements en Gironde et dans les départements limitrophes. L''organisme HLM accompagne ses locataires tout au long de leur parcours résidentiel en proposant des logements accessibles et de qualité. Les alternants y développent des compétences en gestion locative sociale, en relation client et en gestion de patrimoine immobilier.', 'Domofrance a été créé en 1961 dans le contexte de la reconstruction d''après-guerre et du fort besoin en logements pour les classes populaires. Depuis plus de 60 ans, l''organisme a construit et rénové des milliers de logements en Gironde pour répondre aux besoins des ménages modestes et intermédiaires. Filiale du groupe Action Logement, Domofrance continue d''investir dans de nouveaux programmes et dans la réhabilitation de son parc existant.', ARRAY['Solidarité','Accessibilité','Qualité','Durabilité','Engagement territorial'], ARRAY['Gérer la relation locataire au quotidien (entrées, sorties, réclamations)','Instruire les dossiers de candidature et participer aux commissions d''attribution','Assurer le suivi des travaux de maintenance et de réhabilitation','Développer des partenariats avec les collectivités et associations locales'], ARRAY['CDC Habitat','Gironde Habitat','Vilogia','bailleurs sociaux régionaux'], 'Plus de 30 000 logements gérés, présence en Nouvelle-Aquitaine, plus de 500 collaborateurs, filiale Action Logement', 'Domofrance recherche des alternants en BTS PI, bachelor immobilier ou licence pro gestion urbaine. Profils engagés, avec le sens du service public et de bonnes capacités relationnelles.', ARRAY['Qu''est-ce qui vous attire dans le secteur du logement social et les missions d''intérêt général ?','Comment gérez-vous une situation de tension avec un locataire en grande difficulté sociale ?','Décrivez votre compréhension de la mixité sociale et de son importance dans le logement.','Comment conciliez-vous rigueur administrative et bienveillance humaine dans votre travail ?','Quelle importance accordez-vous au développement durable dans un organisme de logement ?'], ARRAY['Quelles sont les différentes catégories de logements HLM (PLAI, PLUS, PLS) et à qui s''adressent-elles ?','Comment fonctionne le système de demande de logement social via le numéro unique ?','Quelles sont les obligations légales du bailleur social en termes de décence du logement ?','Comment participer efficacement à une commission d''attribution de logements sociaux ?'], '20.png', FALSE),
(21, 'CENTURY 21 AML IMMOBILIER', 'Century 21 AML', 'IMMOBILIER', 'Arnaud BAUDUIN', 'ELLUARD Xavier', 'https://www.century21.fr', 'century21.fr', 'Transaction immobilière', 'L''immobilier, c''est notre siècle', '', '', 'Century 21 est le premier réseau immobilier mondial, avec plus de 900 agences en France. L''agence AML Immobilier est une franchisée du réseau implantée en Gironde, offrant des services complets de transaction résidentielle et commerciale. Les alternants y bénéficient de la puissance d''un réseau international tout en travaillant dans une structure à taille humaine.', 'Century 21 a été fondé en 1971 aux États-Unis avant de s''implanter en France dans les années 1980. Le réseau est devenu le premier réseau immobilier mondial grâce à son expansion internationale et à sa franchise structurée. En France, avec plus de 900 agences, Century 21 s''appuie sur des franchisés indépendants comme AML Immobilier qui bénéficient des outils et de la notoriété du groupe tout en gardant leur autonomie entrepreneuriale.', ARRAY['Excellence','Engagement','Innovation','Intégrité','Collaboration'], ARRAY['Prospecter des mandats de vente et de location','Réaliser des estimations de biens et des visites','Accompagner les clients acquéreurs jusqu''à la signature','Assurer le suivi administratif des dossiers de vente'], ARRAY['Orpi','Guy Hoquet','Laforêt','Stéphane Plaza Immobilier','ERA Immobilier'], '1er réseau immobilier mondial, plus de 900 agences en France, plus de 10 000 transactions annuelles en France', 'Century 21 recherche des alternants en BTS PI ou bachelor immobilier. Profils ambitieux, ayant le sens du commerce et une forte motivation pour le métier de négociateur.', ARRAY['Qu''est-ce que la marque Century 21 représente pour vous et pourquoi l''avoir choisie ?','Comment tirez-vous parti de la notoriété d''un réseau international dans votre prospection ?','Décrivez comment vous gérez votre emploi du temps en autonomie en tant que négociateur.','Comment construisez-vous votre réseau de prescripteurs (notaires, banquiers, artisans) ?','Quelle est votre stratégie pour vous démarquer dans un marché immobilier concurrentiel ?'], ARRAY['Quels outils digitaux Century 21 met-il à disposition de ses négociateurs et comment les utiliser ?','Comment réaliser une estimation immobilière précise en combinant méthode comparative et approche terrain ?','Quelles sont les obligations de l''agent immobilier en matière de lutte anti-blanchiment ?','Comment accompagner un primo-accédant dans son plan de financement et son projet d''achat ?'], '21.png', FALSE),
(22, 'CENTURY 21 AML BEGLES', 'Century 21 AML Bègles', 'IMMOBILIER', 'Arnaud BAUDUIN', 'ELLUARD Xavier', 'https://www.century21.fr', 'century21.fr', 'Transaction immobilière', 'Votre projet immobilier à Bègles et ses environs', '', '', 'Century 21 AML Bègles est l''agence du réseau Century 21 spécialisée sur la commune de Bègles et le sud de la Gironde, marché en plein essor porté par la dynamique métropolitaine bordelaise. L''agence offre un accompagnement de qualité pour toutes les transactions immobilières résidentielles. Les alternants y développent une expertise pointue d''un marché local attractif.', 'L''agence Century 21 AML Bègles a été ouverte pour couvrir le marché immobilier de la rive gauche de la Garonne au sud de Bordeaux, un secteur en forte expansion avec le développement de la métropole bordelaise. Sous la direction d''Xavier Elluard, l''agence s''est imposée comme un acteur incontournable des transactions immobilières à Bègles et dans les communes voisines. Elle s''appuie sur la force du réseau Century 21 et une connaissance approfondie du territoire.', ARRAY['Excellence','Proximité','Connaissance terrain','Engagement','Transparence'], ARRAY['Développer la prospection sur le secteur de Bègles et ses environs','Réaliser des estimations et accompagner les vendeurs','Guider les acquéreurs dans leur recherche de bien','Gérer les dossiers de vente jusqu''à la signature notariale'], ARRAY['Orpi Bègles','agences indépendantes locales','IAD','Laforêt','Guy Hoquet'], 'Marché de Bègles en forte croissance, accès tramway et proximité Bordeaux, agence du réseau Century 21', 'L''agence recherche des alternants en BTS PI ou bachelor immobilier avec une connaissance ou un intérêt pour le marché bordelais.', ARRAY['Pourquoi souhaitez-vous travailler sur le marché immobilier de Bègles et du sud bordelais ?','Comment développer une expertise locale pour conseiller efficacement acheteurs et vendeurs ?','Décrivez votre approche pour construire votre réseau de contacts dans un secteur géographique précis.','Comment gérez-vous la relation avec un client vendeur qui surévalue son bien par rapport au marché ?','Qu''est-ce que la connaissance du marché local apporte concrètement à vos clients ?'], ARRAY['Quelles sont les particularités du marché immobilier de la métropole bordelaise et de la rive gauche ?','Comment utiliser les données du marché (prix au m², délais de vente) pour argumenter une estimation ?','Quels sont les avantages et inconvénients pour un acquéreur d''acheter dans le neuf vs l''ancien ?','Comment organiser une journée porte ouverte pour maximiser les visites d''un bien à vendre ?'], '22.png', FALSE),
(23, 'CITYA', 'Citya Immobilier', 'IMMOBILIER', 'Arnaud BAUDUIN', 'EBERLIN Loris', 'https://www.citya.com', 'citya.com', 'Gestion locative et transaction immobilière', 'L''immobilier simplifié', '', '', 'Citya Immobilier est l''un des premiers réseaux français de gestion locative et de transaction, avec plus de 200 agences en France. Le groupe propose une offre complète couvrant la gestion de biens, la transaction et le syndic de copropriété. Les alternants y bénéficient d''une formation structurée dans un réseau à forte notoriété.', 'Citya Immobilier a été fondé à Tours en 1990 et s''est développé pour devenir l''un des leaders nationaux de la gestion immobilière. Le groupe a construit son succès sur une offre intégrée de services immobiliers, de la gestion locative au syndic en passant par la transaction. Avec plus de 200 agences et plusieurs milliers de collaborateurs, Citya est aujourd''hui un acteur de premier plan dont la croissance repose sur un maillage territorial dense.', ARRAY['Simplification','Excellence','Proximité','Innovation','Satisfaction client'], ARRAY['Gérer les biens locatifs (gestion des loyers, relations locataires)','Assurer le suivi des copropriétés (AG, travaux, budgets)','Participer à la transaction immobilière (vente, location)','Conseiller les propriétaires et copropriétaires sur leur patrimoine'], ARRAY['Foncia','Nexity Gestion','BNP Paribas Real Estate Gestion','Oralia'], 'Plus de 200 agences en France, plusieurs milliers de biens gérés, présence dans plus de 50 villes françaises', 'Citya recherche des alternants en BTS PI, licence gestion immobilière ou bachelor immobilier. Profils rigoureux, organisés, avec un intérêt pour le droit et la gestion.', ARRAY['Qu''est-ce qui vous a conduit vers la gestion immobilière au sein d''un grand réseau ?','Comment gérez-vous des situations juridiquement complexes impliquant un locataire et un propriétaire ?','Décrivez votre méthode pour traiter de nombreux dossiers simultanément avec des délais contraints.','Comment maintenez-vous un niveau de qualité de service élevé face à la pression des volumes ?','Quelle est l''importance de la veille juridique et réglementaire dans le métier de gestionnaire immobilier ?'], ARRAY['Quelles sont les principales lois régissant la location immobilière en France (loi ALUR, loi Elan) ?','Comment établir un budget prévisionnel de charges pour une copropriété ?','Quelles sont les étapes d''une assemblée générale de copropriété, de la convocation au procès-verbal ?','Comment gérer un impayé de charges de copropriété en respectant les procédures légales ?'], '23.ico', FALSE),
(24, 'SARL INTENSIMMO GESTION', 'Intensimmo Gestion', 'IMMOBILIER', 'Arnaud BAUDUIN', 'FOURNEAU Gaëlle', 'https://www.intensimmo.fr', 'intens.immo', 'Gestion locative', 'Une gestion immobilière intensive et personnalisée', '', '', 'Intensimmo Gestion est un cabinet spécialisé dans la gestion locative de biens immobiliers résidentiels et commerciaux en Gironde. Il propose aux propriétaires bailleurs une gestion complète et transparente de leur patrimoine. Les alternants y développent une maîtrise approfondie de la gestion locative et du droit des baux.', 'Intensimmo Gestion a été fondé par des professionnels de l''immobilier souhaitant proposer une gestion locative de proximité et sur mesure. En se concentrant sur la gestion patrimoniale, le cabinet a pu développer une expertise pointue au service de propriétaires bailleurs exigeants. La structure à taille humaine permet à chaque client de bénéficier d''un interlocuteur dédié et réactif.', ARRAY['Expertise','Rigueur','Transparence','Proximité','Réactivité'], ARRAY['Gérer les relations locataires (baux, états des lieux, quittances)','Assurer la collecte des loyers et le reversement aux propriétaires','Coordonner les travaux de maintenance et d''entretien','Conseiller les propriétaires sur la valorisation de leur patrimoine'], ARRAY['Cabinets de gestion locative locaux','Citya','Foncia','Oralia'], 'Cabinet spécialisé gestion locative, portefeuille de biens diversifié, double expertise résidentiel et commercial', 'Intensimmo recherche des alternants en BTS PI ou licence immobilier. Profils minutieux, avec un goût pour la gestion administrative et le droit immobilier.', ARRAY['Qu''est-ce qui vous attire dans la gestion de patrimoine immobilier par rapport à la transaction ?','Comment gérez-vous la relation avec un propriétaire très exigeant sur le suivi de son bien ?','Décrivez votre méthode d''organisation pour traiter des dossiers administratifs complexes.','Comment gérez-vous un locataire qui refuse de quitter les lieux à l''expiration de son bail ?','Quelle importance accordez-vous à la mise à jour de vos connaissances juridiques en immobilier ?'], ARRAY['Quelles sont les clauses essentielles d''un bail d''habitation conforme à la loi de 1989 ?','Comment réaliser et formaliser un état des lieux d''entrée et de sortie ?','Quelles sont les charges récupérables auprès du locataire selon la législation française ?','Comment calculer la révision annuelle du loyer selon l''indice IRL ?'], '24.png', FALSE),
(25, 'In''li Sud Ouest', 'In''li Sud Ouest', 'IMMOBILIER', 'Arnaud BAUDUIN', 'LEBLANC Christophe', 'https://www.inli.fr', 'inli.fr', 'Logement intermédiaire', 'Le logement intermédiaire pour les classes moyennes', '', '', 'In''li est un bailleur du groupe Action Logement spécialisé dans le logement intermédiaire, destiné aux classes moyennes qui gagnent trop pour accéder au HLM mais pas assez pour le privé. In''li Sud Ouest développe et gère cette offre en Nouvelle-Aquitaine. Les alternants y découvrent un métier de gestion locative à fort impact social.', 'In''li (pour intermédiaire et logement) a été créé par le groupe Action Logement pour répondre à une zone grise du marché locatif : les ménages aux revenus intermédiaires exclus à la fois du parc social et du marché privé trop cher. La filiale Sud Ouest développe des programmes de logements intermédiaires dans les zones tendues de Nouvelle-Aquitaine, notamment sur la métropole bordelaise. En proposant des loyers inférieurs de 10 à 15% au marché privé, In''li contribue à l''attractivité des territoires.', ARRAY['Accessibilité','Solidarité','Qualité','Engagement territorial','Innovation'], ARRAY['Commercialiser les logements intermédiaires auprès des candidats éligibles','Gérer la relation locataire tout au long du bail','Développer des programmes de logements intermédiaires en partenariat','Accompagner les parcours résidentiels des locataires vers l''accession'], ARRAY['CDC Habitat Intermédiaire','Nexity Studéa','bailleurs privés institutionnels','Domofrance'], 'Filiale Action Logement, présence nationale, loyers 10-15% inférieurs au marché privé, zones tendues', 'In''li recherche des alternants en BTS PI, bachelor immobilier ou licence gestion. Profils sensibles aux enjeux sociaux et désireux d''exercer un métier utile.', ARRAY['Qu''est-ce que le logement intermédiaire et pourquoi répond-il à un besoin social important ?','Comment expliquez-vous le concept de logement intermédiaire à un candidat qui ne le connaît pas ?','Décrivez une situation où vous avez aidé quelqu''un à trouver une solution à un problème complexe.','Comment gérez-vous les candidatures des ménages qui ne remplissent pas les critères d''éligibilité ?','Pourquoi souhaitez-vous travailler pour un acteur du logement avec une mission sociale forte ?'], ARRAY['Quels sont les plafonds de ressources pour accéder au logement intermédiaire et comment les vérifier ?','Comment distinguer logement social, intermédiaire et privé en termes de conditions d''accès et de loyers ?','Quelles sont les étapes de commercialisation d''un programme de logements intermédiaires neufs ?','Comment accompagner un locataire dans son projet d''accession à la propriété ?'], '25.png', FALSE),
(26, 'SYNERGY SCOP', 'Synergy SCOP', 'MARKETING / COM / SOCIAL', 'Hugo Crave', 'ANDRIEU Severine', 'https://www.synergy-scop.fr', 'synergy-scop.fr', 'Communication et conseil en marketing', 'Ensemble, une communication plus forte', '', '', 'Synergy SCOP est une société coopérative et participative (SCOP) spécialisée dans le conseil en communication et marketing. Son modèle coopératif place les salariés au coeur de la gouvernance de l''entreprise. Les alternants y développent des compétences en communication, tout en découvrant un modèle d''entreprise alternatif et engagé.', 'Synergy SCOP a été fondée sous la forme d''une SCOP pour allier efficacité commerciale et gouvernance démocratique. Ce modèle coopératif permet aux salariés d''être associés et de participer aux décisions stratégiques de l''entreprise. La structure a développé une expertise en communication et marketing au service des entreprises et organisations de la région, en valorisant une approche collaborative et innovante.', ARRAY['Coopération','Démocratie','Innovation','Responsabilité','Engagement'], ARRAY['Concevoir et mettre en oeuvre des stratégies de communication','Gérer des projets marketing de A à Z','Produire des contenus créatifs (visuels, textes, vidéos)','Analyser les performances des actions et proposer des ajustements'], ARRAY['Agences de communication locales','indépendants freelance','SCOP communication régionales'], 'SCOP participative, gouvernance démocratique, équipe pluridisciplinaire en communication et marketing', 'Synergy SCOP recherche des alternants en BTS communication, bachelor marketing ou licence info-com. Profils créatifs, engagés et sensibles aux valeurs coopératives.', ARRAY['Qu''est-ce qui vous attire dans le modèle coopératif et participatif d''une SCOP ?','Comment conciliez-vous créativité individuelle et travail collaboratif au sein d''une équipe ?','Décrivez un projet créatif ou de communication dont vous êtes particulièrement fier.','Comment gérez-vous des retours critiques sur votre travail créatif de la part d''un client ?','Quelle est votre vision d''une communication responsable et éthique ?'], ARRAY['Quelles sont les étapes de création d''une stratégie de communication pour une PME ?','Comment mesurer le retour sur investissement d''une campagne de communication digitale ?','Quels outils de création graphique et de gestion des réseaux sociaux maîtrisez-vous ?','Comment adapter un message de communication à différentes cibles et supports ?'], '26.png', FALSE),
(27, 'Eirl Zelimir Bozic', 'Bozic Immobilier', 'MARKETING / COM / SOCIAL', 'Hugo Crave', 'Bozic Zelimir', 'https://www.bozic-immobilier.fr', '', 'Conseil en communication immobilière', 'La communication au service de votre immobilier', '', '', 'Bozic Immobilier est une structure de conseil spécialisée à l''intersection du marketing et de l''immobilier, aidant les professionnels de l''immobilier à développer leur visibilité et leur communication. Zelimir Bozic accompagne ses clients dans la définition de leur identité de marque et de leurs stratégies de communication digitale. C''est une opportunité unique d''apprendre le marketing appliqué au secteur immobilier.', 'Zelimir Bozic a fondé sa structure entrepreneuriale après avoir acquis une double expertise en immobilier et en communication. Convaincu que les professionnels de l''immobilier sous-exploitent les outils de marketing digital, il a développé une offre de conseil sur mesure pour les aider à se démarquer. Son approche combine stratégie de contenu, référencement et développement de la marque personnelle.', ARRAY['Créativité','Expertise','Entrepreneuriat','Innovation digitale','Proximité'], ARRAY['Développer la stratégie de communication digitale de clients immobiliers','Créer et gérer des contenus pour les réseaux sociaux','Conseiller sur le référencement et la visibilité en ligne','Accompagner les clients dans la construction de leur marque'], ARRAY['Agences marketing digitales','consultants freelance','spécialistes du marketing immobilier'], 'Structure entrepreneuriale agile, double expertise marketing et immobilier, clientèle de professionnels de l''immobilier', 'Recherche des alternants en BTS communication, bachelor marketing digital ou licence info-com. Profils créatifs, à l''aise avec les outils numériques et ayant un intérêt pour l''immobilier.', ARRAY['Qu''est-ce qui vous intéresse dans la communication appliquée au secteur immobilier ?','Comment vous tenez-vous informé des nouvelles tendances du marketing digital ?','Décrivez un contenu que vous avez créé pour les réseaux sociaux et analysez ses résultats.','Comment gérez-vous plusieurs clients aux besoins de communication très différents ?','Qu''est-ce que la marque personnelle signifie pour un professionnel de l''immobilier ?'], ARRAY['Quels réseaux sociaux sont les plus pertinents pour un agent immobilier et pourquoi ?','Comment créer une stratégie de contenu efficace pour un professionnel de l''immobilier ?','Quels outils utilisez-vous pour analyser les performances d''une présence sur les réseaux sociaux ?','Comment optimiser le référencement local (SEO) d''un site d''agence immobilière ?'], NULL, FALSE),
(28, 'Agence Pierrot', 'Agence Pierrot', 'MARKETING / COM / SOCIAL', 'Hugo Crave', 'De Roquefeuil Marine', 'https://www.agencepierrot.fr', 'agencepierrot.fr', 'Agence de communication créative', 'La créativité au service de vos marques', '', '', 'L''Agence Pierrot est une agence de communication créative proposant des solutions complètes de branding, design et communication digitale pour les entreprises et institutions. Elle accompagne ses clients de la stratégie à la production de contenus avec une approche créative et personnalisée. Les alternants y développent leur créativité et leur expertise en communication.', 'L''Agence Pierrot a été fondée par des créatifs passionnés souhaitant mettre leur talent au service des marques et des projets qui ont du sens. Ancrée dans le tissu économique régional, l''agence a construit un portfolio de clients variés allant de la start-up à la grande entreprise. En privilégiant les relations durables avec ses clients, Agence Pierrot s''est imposée comme un partenaire créatif de confiance.', ARRAY['Créativité','Originalité','Écoute','Qualité','Passion'], ARRAY['Concevoir des identités visuelles et des supports de communication','Gérer des projets de communication digitale (réseaux sociaux, site web)','Rédiger des contenus créatifs adaptés aux différentes cibles','Accompagner les clients dans leur stratégie de marque'], ARRAY['Agences de communication locales','freelances créatifs','studios graphiques'], 'Agence créative à taille humaine, portfolio clients diversifié, expertise branding et digital', 'Agence Pierrot recherche des alternants en BTS communication ou design, bachelor marketing créatif. Profils créatifs, polyvalents et passionnés par la communication visuelle.', ARRAY['Comment définissez-vous votre sensibilité créative et comment l''exprimez-vous professionnellement ?','Comment gérez-vous les retours critiques d''un client sur une proposition créative que vous défendez ?','Décrivez un projet de communication dont vous avez conçu et géré la réalisation.','Comment vous assurez-vous que votre travail créatif répond bien aux objectifs stratégiques du client ?','Comment restez-vous inspiré et à la pointe des tendances créatives et digitales ?'], ARRAY['Quels logiciels de création graphique maîtrisez-vous (Adobe, Canva, Figma) ?','Comment construire un brief créatif efficace avant de démarrer un projet de communication ?','Quelles sont les étapes de création d''une identité visuelle complète pour une entreprise ?','Comment adapter une charte graphique à des formats digitaux variés (réseaux sociaux, web, mobile) ?'], '28.png', FALSE),
(29, 'Vitaépargne Immobilier Aquitaine', 'Vitaépargne', 'MARKETING / COM / SOCIAL', 'Hugo Crave', 'Denizet Catherine', 'https://www.vitaepargne.fr', 'vitalepargne.com', 'Conseil en investissement immobilier et épargne', 'Investissez dans votre avenir avec sérénité', '', '', 'Vitaépargne Immobilier Aquitaine est un cabinet de conseil spécialisé dans l''investissement immobilier défiscalisant et la gestion de patrimoine en Nouvelle-Aquitaine. Il accompagne ses clients dans la construction de leur patrimoine immobilier via des dispositifs fiscaux avantageux. Les alternants y développent des compétences en conseil patrimonial, marketing financier et relation client.', 'Vitaépargne Immobilier Aquitaine a été fondée pour répondre aux besoins des particuliers souhaitant investir dans l''immobilier avec une optimisation fiscale. En s''appuyant sur une expertise des dispositifs de défiscalisation (Pinel, Malraux, LMNP), le cabinet a construit une clientèle d''investisseurs fidèles en Nouvelle-Aquitaine. La structure continue de se développer en élargissant son offre aux produits d''épargne financière.', ARRAY['Expertise','Confiance','Pédagogie','Intégrité','Performance'], ARRAY['Conseiller les clients sur les dispositifs d''investissement immobilier défiscalisant','Développer la clientèle par la prospection et les recommandations','Présenter des solutions d''épargne et de gestion de patrimoine','Assurer le suivi des clients investisseurs tout au long de leur projet'], ARRAY['Consultants patrimoniaux indépendants','CGP (Conseillers en Gestion de Patrimoine)','banques et assurances proposant de l''investissement'], 'Cabinet spécialisé défiscalisation immobilière, expertise dispositifs Pinel et LMNP, clientèle d''investisseurs particuliers', 'Vitaépargne recherche des alternants en BTS banque/assurance, bachelor commerce ou finance. Profils pédagogues, rigoureux, avec un intérêt pour la fiscalité et le patrimoine.', ARRAY['Qu''est-ce qui vous attire dans le conseil en investissement immobilier et gestion de patrimoine ?','Comment expliquez-vous simplement la défiscalisation immobilière à un client non spécialiste ?','Décrivez votre approche pour construire une relation de conseil à long terme avec un client.','Comment gérez-vous la responsabilité de conseiller quelqu''un sur des décisions financières importantes ?','Quelle importance accordez-vous à la formation continue dans des secteurs très réglementés comme la finance ?'], ARRAY['Quels sont les principaux dispositifs de défiscalisation immobilière en France et leurs conditions ?','Comment calculer la rentabilité nette d''un investissement locatif en tenant compte de la fiscalité ?','Qu''est-ce que le statut LMNP (Loueur Meublé Non Professionnel) et quels sont ses avantages ?','Comment construire un argumentaire commercial pour un produit d''investissement immobilier défiscalisant ?'], '29.png', FALSE),
(30, 'SARL LEROY', 'SARL Leroy', 'MARKETING / COM / SOCIAL', 'Hugo Crave', 'LEROY JEAN-FRANCOIS', 'https://www.sarl-leroy.fr', 'sarlleroy.com', 'Commerce et services aux entreprises', 'Des solutions sur mesure pour votre entreprise', '', '', 'La SARL Leroy est une entreprise locale proposant des services et solutions adaptés aux besoins des entreprises et des particuliers de la région bordelaise. Elle offre un cadre d''apprentissage polyvalent où les alternants peuvent développer des compétences commerciales et en communication. La structure à taille humaine favorise l''autonomie et la montée en compétences rapide.', 'La SARL Leroy a été fondée par Jean-François Leroy avec l''ambition de proposer des services de qualité aux entreprises locales. En s''adaptant constamment aux besoins du marché, la structure a su développer son activité en Gironde. Entreprise familiale et ancrée dans son territoire, elle valorise les relations humaines et la satisfaction de ses clients au quotidien.', ARRAY['Proximité','Flexibilité','Service','Engagement','Fiabilité'], ARRAY['Développer le portefeuille clients de l''entreprise','Assurer la communication et le marketing de la structure','Gérer les relations fournisseurs et partenaires','Contribuer au développement commercial et à la fidélisation'], ARRAY['PME locales du secteur','prestataires de services régionaux'], 'PME locale à taille humaine, ancrage territorial en Gironde, polyvalence des services proposés', 'La SARL Leroy recherche des alternants en BTS NDRC, communication ou marketing. Profils polyvalents, autonomes et débrouillards.', ARRAY['Pourquoi avez-vous choisi de faire votre alternance dans une PME plutôt que dans un grand groupe ?','Comment gérez-vous votre autonomie et votre organisation dans une structure à effectif réduit ?','Décrivez une situation où vous avez dû vous adapter rapidement à une tâche que vous ne connaissiez pas.','Comment contribueriez-vous au développement commercial d''une petite structure ?','Quelles qualités pensez-vous indispensables pour réussir dans une PME ?'], ARRAY['Quels outils digitaux utiliseriez-vous pour améliorer la visibilité en ligne d''une PME locale ?','Comment développer une stratégie commerciale adaptée au budget limité d''une petite entreprise ?','Quelles techniques de prospection sont les plus efficaces pour une PME de services ?','Comment mesurer l''efficacité des actions marketing mises en place dans une petite structure ?'], '30.png', FALSE),
(31, 'Leroy Merlin Mérignac', 'Leroy Merlin', 'MARKETING / COM / SOCIAL', 'Hugo Crave', 'VICTORIN Marie', 'https://www.leroymerlin.fr', 'leroymerlin.fr', 'Grande distribution bricolage et habitat', 'Construire, aménager, décorer : faire la maison', '', '', 'Leroy Merlin est le leader de la grande distribution spécialisée dans le bricolage, l''aménagement et la décoration de la maison en France. Le magasin de Mérignac est l''un des plus importants de la métropole bordelaise, proposant plus de 35 000 références. Les alternants y découvrent les métiers du commerce spécialisé, du marketing opérationnel et du management.', 'Leroy Merlin a été fondé en 1923 à Wattrelos par Adolphe Leroy et Rose Merlin. L''enseigne a connu une forte croissance pour devenir le leader français du bricolage et de l''aménagement de la maison. Appartenant au groupe Adeo, présent dans 13 pays, Leroy Merlin compte plus de 140 magasins en France et emploie plus de 26 000 collaborateurs. L''enseigne est aussi connue pour son modèle participatif qui associe les collaborateurs à la vie de l''entreprise.', ARRAY['Partage','Autonomie','Engagement','Enthousiasme','Respect'], ARRAY['Conseiller les clients dans leurs projets d''aménagement et de bricolage','Assurer la mise en rayon et la gestion des stocks du rayon','Participer aux animations commerciales et aux opérations promotionnelles','Contribuer à la satisfaction et à la fidélisation des clients'], ARRAY['Castorama','Brico Dépôt','Mr Bricolage','Bricomarché','Ikea'], 'Leader français du bricolage, plus de 140 magasins, 26 000 collaborateurs, plus de 35 000 références produits', 'Leroy Merlin recherche des alternants en BTS MCO, marketing ou management. Profils passionnés de l''habitat, autonomes et ayant le sens du conseil client.', ARRAY['Qu''est-ce qui vous attire dans l''univers du bricolage et de l''aménagement de la maison ?','Comment conseillez-vous efficacement un client qui ne sait pas par où commencer son projet de rénovation ?','Décrivez une situation où vous avez su transformer une demande basique en vente complète.','Comment gérez-vous un afflux de clients le week-end tout en maintenant un service de qualité ?','Quelle importance accordez-vous à la connaissance produit dans le métier de vendeur spécialisé ?'], ARRAY['Comment organiser un rayon pour maximiser la visibilité des produits et faciliter l''achat du client ?','Quelles sont les techniques de vente additionnelle (cross-selling, up-selling) applicables dans une GSB ?','Comment gérer efficacement les retours et réclamations clients dans une grande surface de bricolage ?','Comment analyser les données de vente d''un rayon pour optimiser les commandes et éviter les ruptures ?'], '31.png', FALSE),
(32, 'Syrade', 'Syrade', 'MARKETING / COM / SOCIAL', 'Ines Arkouk', 'Alvarez Camille', 'https://www.syrade.fr', 'syrade.com', 'Conseil et services digitaux', 'Le digital au service de votre croissance', '', '', 'Syrade est une agence de conseil et de services digitaux accompagnant les entreprises dans leur transformation numérique et le développement de leur présence en ligne. Elle propose des solutions en marketing digital, création de sites web et stratégie de contenu. Les alternants y développent des compétences polyvalentes dans un environnement digital en constante évolution.', 'Syrade a été fondée par des professionnels du digital souhaitant proposer aux PME une offre de services numériques accessible et efficace. L''agence s''est développée en construisant des partenariats durables avec ses clients, en adoptant une approche conseil avant tout. En combinant expertise technique et sensibilité marketing, Syrade accompagne ses clients dans leur croissance digitale.', ARRAY['Innovation','Agilité','Expertise','Partenariat','Résultats'], ARRAY['Gérer la présence digitale des clients (réseaux sociaux, site web)','Créer des stratégies de contenu et de référencement','Analyser les données et produire des reportings de performance','Participer au développement commercial de l''agence'], ARRAY['Agences digitales locales','freelances marketing digital','agences nationales'], 'Agence digitale en croissance, clients PME et ETI, expertise SEO, réseaux sociaux et création de contenus', 'Syrade recherche des alternants en bachelor marketing digital, BTS communication ou licence MIASHS. Profils analytiques, créatifs et passionnés par le digital.', ARRAY['Qu''est-ce qui vous a donné envie de travailler dans le marketing digital ?','Comment vous tenez-vous informé des évolutions permanentes des algorithmes et outils digitaux ?','Décrivez un projet digital que vous avez mené et analysez ses résultats.','Comment gérez-vous un client qui ne comprend pas la valeur du marketing digital pour son business ?','Comment conciliez-vous créativité de contenu et rigueur analytique dans votre travail ?'], ARRAY['Quelles sont les principales métriques à suivre pour évaluer une stratégie de marketing digital ?','Comment construire une stratégie de contenu pour les réseaux sociaux d''une PME ?','Quels sont les fondamentaux du référencement naturel (SEO) et comment les appliquer ?','Comment gérer une crise de réputation en ligne pour une entreprise cliente ?'], '32.png', FALSE),
(33, 'Nova', 'Nova', 'MARKETING / COM / SOCIAL', 'Lorette', 'Vigier Quentin', 'https://www.nova.fr', '', 'Communication et innovation', 'Innover pour communiquer autrement', '', '', 'Nova est une structure spécialisée dans la communication innovante et les nouvelles formes de création de contenu pour les marques et les organisations. Elle explore les tendances émergentes du marketing pour proposer des approches différenciantes à ses clients. Les alternants y sont encouragés à exprimer leur créativité et à développer leur sens de l''innovation.', 'Nova a été fondée avec la conviction que la communication doit constamment se réinventer pour rester efficace dans un environnement saturé de messages. En explorant de nouveaux formats, de nouvelles plateformes et de nouvelles narrations de marque, Nova propose à ses clients des solutions créatives et impactantes. L''entreprise valorise une culture d''expérimentation et d''apprentissage continu.', ARRAY['Innovation','Créativité','Audace','Curiosité','Impact'], ARRAY['Concevoir des stratégies de communication innovantes','Produire des contenus créatifs pour différents supports','Développer des partenariats avec des créateurs et influenceurs','Analyser les tendances pour anticiper les évolutions du secteur'], ARRAY['Agences de communication créatives','studios de production de contenu','agences digitales innovantes'], 'Structure innovante en développement, approche expérimentale, expertise nouvelles formes de communication', 'Nova recherche des alternants en BTS communication, bachelor marketing créatif ou licence info-com. Profils audacieux, créatifs et passionnés par les nouvelles tendances.', ARRAY['Comment définissez-vous l''innovation en communication et donnez un exemple concret ?','Comment gérez-vous l''échec d''une idée créative sur laquelle vous aviez misé ?','Décrivez votre veille créative : quelles sources, quelles inspirations ?','Comment convaincre un client conservateur d''adopter une approche de communication innovante ?','Qu''est-ce qui différencie selon vous une communication ordinaire d''une communication mémorable ?'], ARRAY['Quelles sont les nouvelles tendances en matière de contenu marketing (short video, podcast, immersif) ?','Comment collaborer efficacement avec des influenceurs pour une campagne de marque ?','Quels critères utilisez-vous pour choisir les bons formats de contenu selon les plateformes ?','Comment mesurer l''impact et l''engagement d''une campagne de communication innovante ?'], NULL, FALSE),
(34, 'le five bordeaux & 4padel', 'Le Five & 4Padel', 'COMMERCE NS', 'Maud BOUHOUFANI', 'ferreira pierre', 'https://www.lefive.fr', 'lefive.fr', 'Loisirs sportifs et padel', 'Le sport, la convivialité, le Five !', '', '', 'Le Five Bordeaux & 4Padel proposent des terrains de football à 5 et de padel en location pour les particuliers et les entreprises, avec une offre d''événements sportifs et de team building. Ces établissements de loisirs sportifs connaissent une forte croissance portée par l''essor du padel en France. Les alternants y développent des compétences en commerce, en gestion et en animation de loisirs sportifs.', 'Le Five est le premier réseau de centres de football à cinq en France, fondé en 2007 à Lyon. Il compte aujourd''hui plus de 80 centres à travers l''Hexagone et s''est diversifié avec l''offre padel, sport en pleine explosion. Le Five Bordeaux propose une expérience sportive complète pour les amateurs de foot à cinq et de padel, avec des tournois, des ligues et des offres entreprises. L''essor du padel en France depuis 2020 a considérablement renforcé l''attractivité de ces centres.', ARRAY['Sport','Convivialité','Accessibilité','Fun','Excellence'], ARRAY['Accueillir et renseigner les clients sur les offres de réservation','Gérer les plannings de terrains et optimiser le taux d''occupation','Développer les offres entreprises et événements sportifs','Participer aux actions commerciales et de fidélisation'], ARRAY['Foot 5 Network','centres de padel indépendants','Padel Academy','complexes sportifs locaux'], '1er réseau français de football à cinq, plus de 80 centres, fort développement padel depuis 2020', 'Le Five recherche des alternants en BTS MCO, management ou animation. Profils sportifs, dynamiques, avec un excellent sens de l''accueil et de la relation client.', ARRAY['Qu''est-ce qui vous attire dans le commerce et la gestion d''un centre de loisirs sportifs ?','Comment développeriez-vous les offres entreprises et team building d''un centre sportif ?','Décrivez comment vous géreriez un pic d''activité un samedi après-midi avec plusieurs équipes attendues.','Comment fidélisez-vous des clients sportifs réguliers pour qu''ils reviennent et recommandent le centre ?','Quelle est votre relation personnelle avec le sport et comment cela enrichit-il votre vision du service ?'], ARRAY['Comment optimiser le taux d''occupation des terrains sur les créneaux moins demandés ?','Quelles actions commerciales mettre en place pour développer les réservations entreprises ?','Comment gérer les réclamations clients liées à des annulations de dernière minute ou des problèmes techniques ?','Quels outils de gestion des réservations et de CRM peut-on utiliser dans un centre sportif ?'], '34.png', FALSE),
(35, 'Action', 'Action', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'FROMONT Maxime / SERVAT Charles-Henry', 'https://www.action.com', 'action.com', 'Commerce discount non-alimentaire', 'Toujours plus pour moins cher', '', '', 'Action est le discounter non-alimentaire à la croissance la plus rapide en Europe, proposant plus de 6 000 références à des prix très compétitifs dans des catégories variées (maison, bricolage, hygiène, papeterie, textile). Avec plus de 750 magasins en France, Action offre des opportunités d''alternance dans le commerce et le management de magasin. C''est un environnement de travail dynamique avec de réelles perspectives d''évolution.', 'Action a été fondé en 1993 aux Pays-Bas et s''est développé à une vitesse fulgurante pour devenir le discounter non-alimentaire numéro 1 en Europe avec plus de 2 500 magasins dans 12 pays. Arrivé en France en 2012, le groupe a connu une expansion remarquable avec plus de 750 magasins en 2024. Le modèle de succès d''Action repose sur une rotation rapide des stocks, des prix très bas et un renouvellement constant de l''offre qui crée une forme d''enthousiasme chez les clients.', ARRAY['Accessibilité','Enthousiasme','Simplicité','Respect','Durabilité'], ARRAY['Assurer la mise en rayon et le réassort des produits','Accueillir et orienter les clients dans le magasin','Participer à la gestion des stocks et aux inventaires','Contribuer au management d''équipe et à la formation des équipiers'], ARRAY['Gifi','Noz','Stokomani','Centrakor','B&M'], 'Plus de 2 500 magasins dans 12 pays, plus de 750 magasins en France, croissance annuelle de 20%, plus de 75 000 collaborateurs', 'Action recherche des alternants en BTS MCO, management ou bachelor commerce. Profils dynamiques, rigoureux et motivés par le commerce à forte rotation.', ARRAY['Qu''est-ce qui vous attire dans le modèle de commerce discount d''Action ?','Comment gérez-vous un travail physique et répétitif tout en maintenant votre engagement ?','Décrivez une situation où vous avez contribué à améliorer l''organisation d''un espace de travail.','Comment expliquez-vous le succès fulgurant d''Action en Europe à des clients qui ne connaissent pas l''enseigne ?','Quelle est votre vision du management d''une équipe en grande distribution ?'], ARRAY['Comment gérer efficacement un processus de mise en rayon rapide pour une grande quantité de produits variés ?','Quels sont les indicateurs de performance clés d''un magasin discount (taux de rupture, rotation des stocks) ?','Comment organiser un inventaire tournant dans un magasin à fort volume de références ?','Quelles sont les techniques pour maintenir un magasin propre et bien rangé avec un flux client élevé ?'], '35.png', FALSE),
(36, 'ALDI', 'ALDI', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'LATOUR Chloé', 'https://www.aldi.fr', 'aldi.fr', 'Grande distribution alimentaire discount', 'Bien manger, bien dépenser', '', '', 'ALDI est l''un des leaders mondiaux de la distribution alimentaire discount, proposant une sélection optimisée de produits de qualité à des prix imbattables. Avec plus de 1 000 magasins en France, le discounter allemand offre des opportunités de carrière en commerce et en management à ses alternants. ALDI est reconnu pour ses conditions de travail attractives et ses perspectives d''évolution rapides.', 'ALDI (ALbrecht DIskont) a été fondé en 1946 par les frères Karl et Theo Albrecht en Allemagne. Le groupe s''est scindé en deux entités (ALDI Nord et ALDI Süd) et s''est développé à l''international pour devenir l''un des premiers distributeurs mondiaux. ALDI est arrivé en France en 1988 et a progressivement imposé son modèle de discount alimentaire, avec une gamme resserrée de produits de qualité à des prix très compétitifs. ALDI France emploie plus de 20 000 collaborateurs.', ARRAY['Qualité','Responsabilité','Fiabilité','Durabilité','Respect'], ARRAY['Assurer la mise en rayon et la gestion des produits alimentaires','Accueillir et encaisser les clients en caisse','Participer à la gestion des stocks et à la réception des marchandises','Contribuer au management et à la formation des équipes'], ARRAY['Lidl','Netto','Leader Price','Carrefour Market','Intermarché'], 'Présent dans plus de 20 pays, plus de 11 000 magasins dans le monde, plus de 1 000 magasins en France, 20 000 collaborateurs en France', 'ALDI recherche des alternants en BTS MCO ou management. Profils rigoureux, polyvalents, avec le sens des responsabilités et l''envie d''évoluer rapidement.', ARRAY['Pourquoi avez-vous choisi ALDI pour votre alternance dans le secteur de la distribution ?','Comment vous adaptez-vous à un environnement de travail où la polyvalence est primordiale ?','Décrivez une situation où vous avez pris des responsabilités au-delà de ce qui vous était demandé.','Comment gérez-vous les périodes de forte activité en magasin (fêtes, promotions) ?','Qu''est-ce qui vous motive dans les perspectives d''évolution rapide proposées par ALDI ?'], ARRAY['Quel est le modèle économique du discount alimentaire et quels sont ses avantages concurrentiels ?','Comment gérer une rupture de stock importante sur un produit phare en période de promotion ?','Quelles sont les réglementations à respecter pour la gestion des produits alimentaires (dates de péremption, chaîne du froid) ?','Comment former et motiver une équipe d''équipiers dans un contexte de forte rotation du personnel ?'], '36.png', FALSE),
(37, 'Chubb Fire & Security', 'Chubb Fire & Security', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'Capes Laëtitia', 'https://chubbfs.com/fr-fr/', 'chubbfs.com', 'Sécurité incendie & sûreté électronique', 'Nous travaillons à rendre le monde plus sûr', '', '', 'Chubb Fire & Security est l''un des leaders mondiaux de la protection incendie et de la sûreté électronique, avec plus de 200 ans d''histoire depuis 1818. En France, Chubb propose des solutions complètes de détection incendie, extincteurs (marque SICLI), systèmes anti-intrusion, vidéosurveillance, contrôle d''accès et téléassistance. Avec 12 000 collaborateurs dans 17 pays et plus de 200 agences, Chubb protège entreprises, administrations, hôpitaux, écoles et particuliers. L''entreprise fait partie du groupe APi Group Corporation.', 'Fondée en 1818 par Charles et Jeremiah Chubb qui inventent la première serrure haute sécurité « Detector Lock », Chubb a révolutionné la sécurité pendant plus de 200 ans. En France, la marque SICLI cumule près de 100 ans d''histoire avec une flotte de 4 millions d''extincteurs. En 1973, Chubb Delta voit le jour à Lyon. En 1979, Chubb Delta devient le premier installateur certifié APSAD en France. Aujourd''hui, Chubb fait partie d''APi Group Corporation et emploie 12 000 personnes dans 17 pays.', ARRAY['Préserver les valeurs humaines','Impulser l''innovation','Viser l''excellence','Agir avec énergie','Gagner avec intégrité'], ARRAY['Concevoir, installer et maintenir des systèmes de protection incendie (détection, suppression, extincteurs SICLI, signalisation)','Déployer des solutions de sûreté électronique (anti-intrusion, vidéosurveillance, contrôle d''accès)','Assurer la télésurveillance et la téléassistance 24h/24 via plus de 20 centres de téléassistance','Former les équipes à la sécurité incendie (SST, évacuation, maniement extincteurs) avec 50+ formateurs et 26 unités mobiles','Proposer des services connectés via la plateforme Chubb VisiON+','Réaliser des audits de sécurité et des expertises techniques pour tous secteurs'], ARRAY['Securitas','Veolia','Siemens Building Technologies','Bosch Security','Johnson Controls'], '12 000 collaborateurs — 17 pays — 200+ agences — 200 ans d''histoire (depuis 1818) — 4 millions d''extincteurs SICLI — 250 000 clients — Indice Égalité Femmes/Hommes 94/100 (2025)', 'Chubb Fire & Security recrute des alternants en BTS ou Bachelor dans les domaines de la sécurité, de l''électronique, du commerce B2B et de la maintenance. Les profils techniques (systèmes de détection, câblage, maintenance), commerciaux (chargés d''affaires, technico-commerciaux) et administratifs sont recherchés. L''entreprise valorise la curiosité technique, le sens du service client et la rigueur. Une forte mobilité terrain est attendue.', ARRAY['Qu''est-ce qui vous attire dans le secteur de la sécurité incendie et de la sûreté électronique ?','Comment réagissez-vous face à des situations d''urgence ou de pression ?','Décrivez une expérience où vous avez fait preuve de rigueur dans un contexte technique.','En quoi la valeur « rendre le monde plus sûr » résonne-t-elle avec votre projet professionnel ?','Comment gérez-vous votre organisation quand vous avez plusieurs interventions à planifier ?'], ARRAY['Quelle est la différence entre un système de détection incendie et un système de suppression automatique ?','Quels équipements de sécurité sont obligatoires dans un ERP (Établissement Recevant du Public) ?','Comment fonctionne un système de vidéosurveillance IP ?','Qu''est-ce que la norme APSAD et pourquoi est-elle importante dans le métier de Chubb ?','Quelles sont les principales menaces de sécurité pour une entreprise industrielle ?'], '37.svg', FALSE),
(38, 'Perrine et Antoinette', 'Perrine et Antoinette', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'Clary Léa', 'https://www.perrineetantoinette.fr', 'perrineetantoinette.com', 'Commerce de détail mode et maison', 'Des créations uniques qui racontent une histoire', '', '', 'Perrine et Antoinette est une boutique de commerce de détail proposant une sélection soignée de créations artisanales, de mode et d''objets pour la maison. L''enseigne mise sur l''authenticité, la qualité et la singularité de ses produits pour offrir une expérience d''achat différente. Les alternants y apprennent les métiers du commerce de détail haut de gamme et de la relation client dans un univers créatif.', 'Perrine et Antoinette a été créée avec la passion de proposer des produits uniques, choisis avec soin pour leur qualité artisanale et leur esthétique. La boutique s''est positionnée sur le segment du commerce de détail qualitatif, à contre-courant de la grande consommation. En développant une identité forte et une clientèle fidèle sensible à l''artisanat et à l''originalité, Perrine et Antoinette est devenu un nom reconnu dans son secteur.', ARRAY['Authenticité','Créativité','Qualité','Bienveillance','Originalité'], ARRAY['Accueillir et conseiller les clients dans leurs achats','Mettre en valeur les produits et assurer la présentation de la boutique','Gérer les stocks et les relations avec les fournisseurs artisans','Participer aux actions de communication et aux événements de la boutique'], ARRAY['Boutiques de créateurs indépendants','concept stores','Maisons du Monde','boutiques artisanales locales'], 'Commerce de détail qualitatif, sélection de créateurs artisans, expérience client différenciante', 'Perrine et Antoinette recherche des alternants en BTS MCO ou commerce. Profils ayant une sensibilité esthétique, le goût de la relation client et un intérêt pour l''artisanat.', ARRAY['Qu''est-ce qui vous attire dans le commerce de détail qualitatif et artisanal ?','Comment développez-vous un argumentaire de vente autour de produits artisanaux et uniques ?','Décrivez votre sensibilité esthétique et comment elle influence votre approche du merchandising.','Comment fidélisez-vous une clientèle sensible à l''authenticité et à la qualité ?','Comment gérez-vous la relation avec des artisans fournisseurs aux contraintes de production spécifiques ?'], ARRAY['Quelles techniques de visual merchandising mettre en oeuvre pour mettre en valeur des produits artisanaux ?','Comment construire une relation commerciale pérenne avec des petits créateurs et artisans ?','Quels outils de communication utiliser pour promouvoir une boutique de commerce créatif en ligne ?','Comment gérer les stocks dans une boutique proposant des produits en édition limitée ou artisanaux ?'], '38.png', FALSE),
(39, 'COMMUNICA ORGANISATION - PREVENTICA', 'Preventica', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'FAUCHON CHARLOTTE', 'https://www.preventica.com', 'preventica.com', 'Événementiel et salons professionnels santé/sécurité', 'Le rendez-vous des professionnels de la prévention', '', '', 'Preventica est le premier salon professionnel dédié à la santé et à la sécurité au travail en France, organisé par Communica Organisation dans plusieurs grandes villes. L''événement rassemble exposants, experts et professionnels des ressources humaines pour traiter des enjeux de prévention des risques professionnels. Les alternants y développent des compétences en organisation événementielle, en commercial B2B et en marketing.', 'Communica Organisation a créé le salon Preventica dans les années 2000 pour répondre à un besoin croissant des entreprises de se former et de s''équiper en matière de santé et sécurité au travail. Le salon se décline aujourd''hui dans plusieurs villes françaises dont Lyon, Bordeaux et Paris. Preventica est devenu la référence du secteur HSE (Hygiène, Sécurité, Environnement) et accueille chaque édition des milliers de visiteurs professionnels et des centaines d''exposants.', ARRAY['Prévention','Innovation','Professionnalisme','Partage','Engagement'], ARRAY['Commercialiser les espaces exposants auprès des entreprises du secteur HSE','Organiser et coordonner les événements professionnels','Gérer les relations exposants et visiteurs','Contribuer aux actions marketing et de communication des salons'], ARRAY['Salons professionnels concurrents en HSE','événements sectoriels INRS','congrès professionnels santé-travail'], '1er salon professionnel HSE en France, plusieurs éditions annuelles dans différentes villes, milliers de visiteurs professionnels, centaines d''exposants', 'Preventica recherche des alternants en BTS NDRC, événementiel ou communication. Profils organisés, à l''aise en B2B, avec le goût de la gestion de projet.', ARRAY['Qu''est-ce qui vous attire dans l''organisation d''événements professionnels dans le domaine de la prévention ?','Comment gérez-vous plusieurs projets événementiels simultanés avec des contraintes de délais serrés ?','Décrivez une expérience d''organisation d''événement dont vous êtes fier.','Comment gérez-vous une situation de crise lors d''un événement professionnel (annulation d''exposant, problème logistique) ?','Quelle est votre approche pour développer une relation commerciale durable avec des exposants fidèles ?'], ARRAY['Quelles sont les étapes clés de l''organisation d''un salon professionnel, du concept à la clôture ?','Comment prospecter et convaincre des entreprises d''exposer lors d''un salon professionnel B2B ?','Quels outils de gestion de projet utilisez-vous pour coordonner un événement de grande envergure ?','Comment mesurer le succès d''un salon professionnel et améliorer l''édition suivante ?'], '39.png', FALSE),
(40, 'BOULANGER', 'Boulanger', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'FRANZON CORENTIN', 'https://www.boulanger.com', 'boulanger.com', 'Commerce d''électroménager et d''électronique grand public', 'Passionnément tech', '', '', 'Boulanger est l''un des leaders français de la distribution d''électroménager, de multimédia et de produits high-tech, avec plus de 170 magasins en France. L''enseigne se distingue par son expertise produit, son service client de qualité et sa forte culture d''entreprise. Les alternants y développent des compétences en conseil technique, en vente et en management.', 'Boulanger a été fondé en 1954 à Lille par la famille Mulliez. L''enseigne a connu une forte croissance pour s''imposer comme le spécialiste de référence de l''électronique grand public en France. Appartenant au groupe Mulliez (comme Auchan ou Leroy Merlin), Boulanger s''est distingué par son modèle participatif et sa culture d''entreprise forte, valorisant l''expertise de ses collaborateurs et leur passion pour la technologie. Boulanger emploie plus de 9 000 collaborateurs.', ARRAY['Passion','Expertise','Service','Partage','Innovation'], ARRAY['Conseiller les clients sur les produits électroménagers et high-tech','Assurer la démonstration et l''argumentation des produits','Gérer les stocks et participer aux inventaires du rayon','Contribuer aux services après-vente et à la satisfaction client'], ARRAY['Fnac Darty','MediaMarkt','Electro Dépôt','Amazon','Cdiscount'], 'Plus de 170 magasins en France, plus de 9 000 collaborateurs, groupe Mulliez, leader sur plusieurs catégories de produits', 'Boulanger recherche des alternants en BTS MCO, management ou bachelor commerce. Profils passionnés par la tech, avec un excellent sens du conseil client.', ARRAY['Qu''est-ce qui vous passionne dans l''univers de la tech et de l''électronique grand public ?','Comment vous assurez-vous de maintenir votre niveau de connaissance des nouveaux produits dans un secteur qui évolue rapidement ?','Décrivez votre approche pour conseiller un client qui ne sait pas quel produit choisir.','Comment gérez-vous un client déçu par un produit qu''il a acheté et qui revient en magasin ?','Qu''est-ce que la culture d''entreprise Boulanger représente pour vous ?'], ARRAY['Comment construire un argumentaire de vente sur un téléviseur haut de gamme face à un client profane ?','Quelles sont les techniques de vente de services additionnels (assurance, installation, reprise) dans un magasin high-tech ?','Comment gérer le SAV (Service Après-Vente) et les échanges de produits défectueux selon la réglementation ?','Comment analyser les résultats de vente d''un rayon pour optimiser l''assortiment et les promotions ?'], '40.png', FALSE),
(42, 'CASTORAMA VILLENAVE D''ORNON', 'Castorama', 'COMMERCE WILL', 'Maud BOUHOUFANI', 'HILLEBRAND Alexandre', 'https://www.castorama.fr', 'castorama.fr', 'Grande surface de bricolage', 'Donnez de la vie à vos idées', '', '', 'Castorama est l''un des leaders de la grande distribution de bricolage, jardinage et décoration en France, appartenant au groupe Kingfisher. Le magasin de Villenave d''Ornon est implanté dans la zone commerciale du sud bordelais et propose une offre complète de plus de 25 000 références. Les alternants y développent des compétences en conseil technique, en vente et en gestion de rayon.', 'Castorama a été fondé en 1969 à Templemars dans le Nord de la France. L''enseigne s''est développée pour devenir l''un des leaders français du bricolage, avant d''intégrer le groupe britannique Kingfisher. Avec plus de 100 magasins en France, Castorama a profondément marqué le paysage commercial français et accompagné des générations de bricoleurs dans leurs projets. L''enseigne investit dans la formation de ses collaborateurs et dans le développement de services pour les particuliers et les professionnels.', ARRAY['Passion','Expertise','Service','Innovation','Durabilité'], ARRAY['Conseiller les clients dans leurs projets de bricolage et de rénovation','Assurer la gestion des stocks et le réassort du rayon','Réaliser des démonstrations produits et des ateliers bricolage','Participer aux opérations commerciales et aux promotions'], ARRAY['Leroy Merlin','Brico Dépôt','Mr Bricolage','Bricomarché','Ikea'], 'Plus de 100 magasins en France, groupe Kingfisher, plus de 25 000 références, présence internationale', 'Castorama recherche des alternants en BTS MCO ou management. Profils passionnés de bricolage et de rénovation, ayant le sens du conseil et de la relation client.', ARRAY['Qu''est-ce qui vous attire dans l''univers du bricolage et de la rénovation ?','Comment conseillez-vous un débutant en bricolage qui ne sait pas par où commencer son projet ?','Décrivez une situation où votre connaissance technique a été déterminante pour satisfaire un client.','Comment gérez-vous un client professionnel (artisan) aux exigences très spécifiques ?','Quelle est votre vision du service après-vente dans une grande surface spécialisée ?'], ARRAY['Comment organiser et animer un atelier bricolage pour des clients débutants ?','Quelles sont les normes de sécurité à respecter pour la vente de produits chimiques et d''outils potentiellement dangereux ?','Comment gérer les ruptures de stock sur des références techniques très demandées ?','Quelles techniques de cross-selling appliquer pour augmenter le panier moyen sur un projet de rénovation ?'], '42.png', FALSE),
(44, 'AUXI LIFE', 'Auxi''life', 'SOCIAL', 'Sarah Delpech', 'Dall''ara Laetitia', 'https://www.auxilife.fr', 'auxilife.fr', 'Aide à domicile et services à la personne', 'Accompagner avec coeur, à chaque instant', '', '', 'Auxi''life est un réseau de services à la personne spécialisé dans l''aide à domicile pour les personnes âgées, handicapées ou en situation de dépendance. Le réseau propose un accompagnement global et humain permettant aux bénéficiaires de rester à leur domicile dans les meilleures conditions. Les alternants y développent des compétences dans le secteur social, le management de proximité et la coordination des interventions.', 'Auxi''life a été fondé avec la conviction que chaque personne fragile mérite un accompagnement digne et personnalisé à son domicile. Le réseau s''est développé en structurant des équipes d''auxiliaires de vie formées et encadrées pour garantir la qualité des interventions. Engagé dans une démarche d''amélioration continue, Auxi''life a développé une réputation solide dans le secteur des services à la personne, un domaine en forte croissance face au vieillissement de la population.', ARRAY['Bienveillance','Respect','Dignité','Engagement','Qualité'], ARRAY['Coordonner les interventions des auxiliaires de vie au domicile des bénéficiaires','Évaluer les besoins des personnes aidées et adapter les plans d''aide','Recruter, former et manager les équipes d''auxiliaires','Développer les partenariats avec les acteurs médico-sociaux du territoire'], ARRAY['Adhap','Azaé','O2 Care Services','Domaliance','Vitalliance'], 'Réseau en croissance dans les services à la personne, secteur en forte demande face au vieillissement de la population', 'Auxi''life recherche des alternants en licence ou bachelor management social, coordination de services à domicile. Profils empathiques, organisés et engagés dans le secteur social.', ARRAY['Qu''est-ce qui vous a orienté vers le secteur de l''aide à domicile et des services à la personne ?','Comment gérez-vous émotionnellement l''accompagnement de personnes en situation de grande fragilité ?','Décrivez votre conception de la dignité et du respect dans l''aide aux personnes dépendantes.','Comment gérez-vous une situation d''urgence ou de conflit au domicile d''un bénéficiaire ?','Pourquoi est-il important pour vous de travailler dans un secteur à forte utilité sociale ?'], ARRAY['Qu''est-ce qu''un plan d''aide personnalisé et comment le construire avec la personne aidée et sa famille ?','Comment coordonner une équipe d''auxiliaires de vie pour assurer la continuité des interventions 7j/7 ?','Quelles sont les réglementations encadrant les services à domicile (agrément, certification Qualiopi) ?','Comment repérer et signaler des situations de maltraitance ou de négligence au domicile d''un bénéficiaire ?'], '44.png', FALSE),
(45, 'MACSF ASSURANCES', 'MACSF', 'BANQUE / ASSURANCE', 'Thomas Gros', 'BUGEAUD SALIMATOU', 'https://www.macsf.fr', 'macsf.fr', 'Assurance et prévoyance pour professionnels de santé', 'Nous protégeons les professionnels de santé', '', '', 'La MACSF est la mutuelle de référence des professionnels de santé en France, couvrant médecins, infirmiers, kinésithérapeutes et tous les soignants. Elle propose des solutions d''assurance professionnelle (responsabilité civile médicale), de prévoyance et d''épargne spécialement conçues pour ce secteur. Les alternants y développent des compétences en vente de produits d''assurance dans un marché de niche très spécialisé.', 'Fondée en 1935, la MACSF (Mutuelle d''Assurance du Corps de Santé Français) a été créée par et pour les professionnels de santé. Elle s''est développée pour devenir l''assureur de référence du secteur médical et paramédical en France, couvrant plus d''un million de sociétaires. Son modèle mutualiste lui permet de proposer des solutions adaptées aux risques spécifiques des professions de santé, notamment en matière de responsabilité civile professionnelle.', ARRAY['Solidarité mutualiste','Expertise','Confiance','Protection','Engagement'], ARRAY['Prospecter et conseiller les professionnels de santé sur leurs besoins d''assurance','Gérer les contrats et les dossiers de sinistres des sociétaires','Développer le portefeuille de membres dans la région','Accompagner les professionnels de santé dans leur installation'], ARRAY['Allianz','AXA Professions de santé','MMA','April Santé','Groupama'], 'Plus d''un million de sociétaires professionnels de santé, fondée en 1935, 1er assureur des professions de santé en France', 'La MACSF recherche des alternants en BTS assurance, licence banque-assurance ou bachelor finance. Profils rigoureux, à l''aise avec les univers médical et financier.', ARRAY['Qu''est-ce qui vous attire dans le conseil aux professionnels de santé en matière d''assurance ?','Comment vous adaptez-vous à un vocabulaire et des problématiques très spécifiques à un secteur professionnel ?','Décrivez votre approche pour établir la confiance avec des professionnels de santé très sollicités.','Comment gérez-vous une situation où un professionnel de santé fait face à une mise en cause de sa responsabilité ?','Quelle est l''importance du modèle mutualiste par rapport à l''assurance commerciale classique ?'], ARRAY['Qu''est-ce que la responsabilité civile médicale et pourquoi est-elle indispensable pour un professionnel de santé ?','Quelles sont les spécificités de l''assurance prévoyance pour un professionnel de santé libéral ?','Comment construire un bilan patrimonial adapté aux besoins d''un médecin s''installant en libéral ?','Quels sont les risques professionnels spécifiques aux différentes professions de santé (médecin, infirmier, kiné) ?'], '45.png', FALSE),
(46, 'ANESTA', 'Anesta', 'BANQUE / ASSURANCE', 'Thomas Gros', 'ARCHAOUI Mohamed', 'https://www.anesta.fr', '', 'Courtage en assurance', 'Votre courtier indépendant en assurance', '', '', 'Anesta est un cabinet de courtage en assurance indépendant, spécialisé dans la recherche des meilleures solutions d''assurance pour les particuliers et les professionnels. En tant qu''intermédiaire, Anesta compare les offres du marché pour proposer à ses clients les garanties les plus adaptées aux meilleurs prix. Les alternants y développent une expertise complète en produits d''assurance et en conseil patrimonial.', 'Anesta a été créé pour offrir aux particuliers et aux professionnels un accompagnement indépendant dans leurs choix d''assurance. En s''affranchissant de tout lien exclusif avec un assureur, le cabinet peut comparer objectivement les offres du marché pour le seul intérêt de ses clients. La structure a construit sa réputation sur la qualité de son conseil et la transparence de sa rémunération.', ARRAY['Indépendance','Transparence','Expertise','Conseil','Fidélité'], ARRAY['Analyser les besoins d''assurance des clients particuliers et professionnels','Comparer les offres du marché et recommander les meilleures solutions','Gérer les contrats et assurer le suivi des sinistres','Développer le portefeuille clients par la prospection et les recommandations'], ARRAY['Assureurs directs (AXA, Allianz, MMA)','autres courtiers indépendants','comparateurs en ligne (LeLynx, AssurLand)'], 'Cabinet de courtage indépendant, accès à plusieurs dizaines de compagnies d''assurance, expertise multi-produits', 'Anesta recherche des alternants en BTS assurance ou licence banque-assurance. Profils analytiques, pédagogues et intéressés par le conseil patrimonial.', ARRAY['Qu''est-ce qui vous attire dans le métier de courtier en assurance par rapport à un conseiller en agence ?','Comment valorisez-vous votre indépendance et votre objectivité auprès des clients ?','Décrivez votre méthode pour analyser les besoins d''un client en matière d''assurance.','Comment gérez-vous la complexité des produits d''assurance pour rendre votre conseil accessible ?','Quelle est l''importance de la mise à jour permanente de vos connaissances dans le secteur de l''assurance ?'], ARRAY['Quelle est la différence entre un courtier en assurance et un agent général d''assurance ?','Quelles sont les principales familles de produits d''assurance (IARD, vie, prévoyance) et leurs caractéristiques ?','Comment analyser un contrat d''assurance pour identifier ses lacunes et proposer des améliorations ?','Quelles sont les obligations réglementaires d''un courtier en assurance (immatriculation ORIAS, devoir de conseil) ?'], '46.svg', FALSE),
(47, 'Smabtp', 'Smabtp', 'BANQUE / ASSURANCE', 'Thomas Gros', 'Deleskiewicz Sabrina', 'https://www.smabtp.fr', 'smabtp.fr', 'Assurance spécialisée BTP', 'L''assureur référent du bâtiment et des travaux publics', '', '', 'Smabtp est le groupe mutualiste de référence dans l''assurance des professionnels du bâtiment et des travaux publics en France. Il propose des solutions d''assurance spécialisées (décennale, tous risques chantier, RC) adaptées aux risques spécifiques du secteur de la construction. Les alternants y développent une expertise unique à la croisée du monde de l''assurance et du BTP.', 'Smabtp a été fondé en 1859 par des artisans et entrepreneurs du bâtiment souhaitant se protéger mutuellement contre les risques de leur métier. Depuis plus de 160 ans, le groupe mutualiste s''est spécialisé dans les besoins d''assurance des professionnels de la construction, devenant l''acteur de référence du secteur. Avec plus de 90 000 entreprises adhérentes, Smabtp couvre une large part du marché de la construction en France.', ARRAY['Solidarité mutualiste','Expertise','Proximité','Fiabilité','Engagement'], ARRAY['Conseiller les professionnels du BTP sur leurs besoins d''assurance','Gérer les contrats et les sinistres des entreprises adhérentes','Développer le portefeuille de membres dans la région','Accompagner les artisans et entrepreneurs dans leur couverture de risques'], ARRAY['Groupama','Allianz','MMA','Axa BTP','Generali'], 'Plus de 90 000 entreprises adhérentes, fondé en 1859, groupe mutualiste de référence BTP, plus de 165 ans d''existence', 'Smabtp recherche des alternants en BTS assurance, licence banque-assurance ou bachelor finance. Profils rigoureux avec un intérêt pour le secteur de la construction.', ARRAY['Qu''est-ce qui vous attire dans l''assurance spécialisée pour le secteur du BTP ?','Comment vous adaptez-vous à un vocabulaire technique propre au bâtiment et à la construction ?','Décrivez votre approche pour conseiller un artisan sur sa couverture d''assurance professionnelle.','Comment gérez-vous un sinistre complexe impliquant plusieurs entreprises sur un chantier ?','Quelle est l''importance de la spécialisation sectorielle dans le métier de conseiller en assurance ?'], ARRAY['Qu''est-ce que l''assurance décennale et pourquoi est-elle obligatoire dans le secteur du BTP ?','Quelles sont les différentes garanties d''assurance indispensables pour une entreprise du bâtiment ?','Comment évaluer les risques d''un chantier pour proposer une assurance tous risques chantier adaptée ?','Qu''est-ce que la garantie dommages-ouvrage et en quoi protège-t-elle le maître d''ouvrage ?'], '47.png', FALSE),
(48, 'SG', 'Société Générale', 'BANQUE / ASSURANCE', 'Thomas Gros', 'Ferrer Christine', 'https://www.societegenerale.fr', 'societegenerale.fr', 'Banque de détail et services financiers', 'Une banque qui vous ressemble', '', '', 'La Société Générale est l''une des plus grandes banques françaises et européennes, offrant une gamme complète de services bancaires et financiers aux particuliers, professionnels et entreprises. En France, son réseau de plus de 2 000 agences constitue l''un des plus denses du pays. Les alternants y développent des compétences en conseil bancaire, en gestion de relation client et en analyse financière.', 'Fondée en 1864, la Société Générale est l''une des plus anciennes banques françaises. Ayant survécu aux crises et aux guerres, elle s''est développée pour devenir un acteur mondial de la banque et des services financiers, présent dans plus de 65 pays. Aujourd''hui connue sous le nom SG, la banque a entrepris une transformation digitale ambitieuse pour moderniser son réseau et ses services. Elle emploie plus de 117 000 collaborateurs dans le monde.', ARRAY['Engagement','Responsabilité','Innovation','Esprit d''équipe','Durabilité'], ARRAY['Accueillir et conseiller les clients sur leurs besoins bancaires','Gérer et développer un portefeuille de clients particuliers','Analyser les demandes de crédit et instruire les dossiers','Promouvoir les produits et services bancaires adaptés'], ARRAY['BNP Paribas','Crédit Agricole','Banque Populaire','LCL','CIC'], 'Plus de 2 000 agences en France, 117 000 collaborateurs dans le monde, présence dans plus de 65 pays, fondée en 1864', 'SG recherche des alternants en BTS Banque, licence ou bachelor banque-assurance, BUT GEA. Profils rigoureux, relationnels et désireux d''évoluer dans l''univers bancaire.', ARRAY['Pourquoi avez-vous choisi la banque de détail pour démarrer votre parcours professionnel ?','Comment établissez-vous une relation de confiance avec un client bancaire sur le long terme ?','Décrivez votre capacité à gérer simultanément des missions administratives et des entretiens clients.','Comment gérez-vous un client en difficulté financière qui sollicite un crédit ?','Quelle est votre vision de la transformation digitale de la banque de détail ?'], ARRAY['Quelles sont les principales familles de produits bancaires proposés à un particulier (épargne, crédit, assurance) ?','Comment analyser le profil financier d''un client pour lui proposer des solutions d''épargne adaptées ?','Quelles sont les réglementations clés encadrant l''octroi de crédits aux particuliers (loi Lagarde, loi Scrivener) ?','Qu''est-ce que la conformité bancaire (KYC, lutte anti-blanchiment) et pourquoi est-elle primordiale ?'], '48.svg', FALSE),
(49, 'BPCE', 'BPCE', 'BANQUE / ASSURANCE', 'Thomas Gros', 'RABOT CASSANDRA', 'https://www.bpce.fr', 'bpce.fr', 'Banque coopérative et services financiers', 'Au coeur de l''économie régionale', '', '', 'BPCE est le 2ème groupe bancaire en France, regroupant les réseaux Banque Populaire et Caisse d''Epargne. Le groupe, à l''architecture coopérative et régionale, est présent dans toutes les régions françaises avec plus de 7 000 agences. Les alternants y développent une expertise complète en banque de détail dans un groupe à forte culture coopérative.', 'Le groupe BPCE est né en 2009 de la fusion des groupes Caisse d''Epargne et Banque Populaire, deux réseaux coopératifs aux longues histoires. La Caisse d''Epargne a été fondée en 1818 et la Banque Populaire en 1917, toutes deux avec une vocation de proximité et d''ancrage territorial. Ensemble, elles constituent le 2ème groupe bancaire français avec plus de 100 000 collaborateurs et des milliers d''actionnaires coopératifs. Le groupe détient également Natixis, sa banque de financement et d''investissement.', ARRAY['Coopération','Proximité','Responsabilité','Engagement territorial','Innovation'], ARRAY['Conseiller et accompagner les clients dans leurs projets bancaires','Développer et gérer un portefeuille de clients particuliers ou professionnels','Instruire les dossiers de crédit et d''épargne','Participer au développement commercial de l''agence'], ARRAY['Crédit Agricole','BNP Paribas','Société Générale','LCL','Crédit Mutuel'], '2ème groupe bancaire en France, plus de 7 000 agences, plus de 100 000 collaborateurs, réseaux Banque Populaire et Caisse d''Epargne', 'BPCE recherche des alternants en BTS Banque, licence banque-assurance ou bachelor finance. Profils relationnels, rigoureux et sensibles au modèle coopératif.', ARRAY['Qu''est-ce que le modèle coopératif de BPCE représente pour vous et pourquoi l''avez-vous choisi ?','Comment décrivez-vous la différence entre une banque coopérative et une banque commerciale classique ?','Décrivez une situation où vous avez su écouter et reformuler les besoins d''un interlocuteur.','Comment gérez-vous la relation avec un client qui traverse une période financière difficile ?','Quelle est l''importance de l''ancrage territorial dans le modèle d''une banque régionale ?'], ARRAY['Quels sont les produits d''épargne réglementée proposés par les Caisses d''Epargne (Livret A, PEL, CEL) et leurs caractéristiques ?','Comment accompagner un client primo-accédant dans son projet d''achat immobilier, du financement à la signature ?','Qu''est-ce que le modèle coopératif implique en termes de gouvernance et de relation avec les sociétaires ?','Quelles sont les étapes d''instruction d''un dossier de crédit à la consommation ?'], '49.png', FALSE),
(50, 'AXA PREVOYANCE ET PATRIMOINE', 'AXA Prévoyance & Patrimoine', 'BANQUE / ASSURANCE', 'Thomas Gros', 'BLANC DAVID', 'https://www.axa.fr', 'axa.fr', 'Assurance, prévoyance et gestion de patrimoine', 'Accompagner votre vie, protéger votre avenir', '', '', 'AXA Prévoyance et Patrimoine est la branche spécialisée du groupe AXA dédiée à la prévoyance individuelle et à la gestion de patrimoine pour les particuliers et les professionnels. Elle propose des solutions complètes d''assurance vie, de prévoyance et de conseil patrimonial. Les alternants y développent une expertise pointue en produits financiers et en conseil patrimonial.', 'AXA est l''un des premiers groupes d''assurance mondiaux, fondé en France en 1817 sous le nom de Mutuelle Assurance des Propriétaires. Après plusieurs fusions, le groupe a adopté le nom AXA en 1985 et est devenu un leader mondial de l''assurance et de la gestion d''actifs. La division Prévoyance et Patrimoine accompagne des millions de clients dans la construction de leur protection sociale et la valorisation de leur patrimoine. AXA emploie plus de 150 000 personnes dans le monde.', ARRAY['Protection','Innovation','Professionnalisme','Intégrité','Solidarité'], ARRAY['Conseiller les clients sur leurs besoins de prévoyance et d''épargne','Réaliser des bilans patrimoniaux et proposer des solutions adaptées','Développer un portefeuille de clients sur le long terme','Assurer le suivi des contrats et l''accompagnement des clients'], ARRAY['Allianz','Generali','CNP Assurances','Swiss Life','Crédit Agricole Assurances'], '1er assureur européen, présent dans plus de 50 pays, plus de 150 000 collaborateurs, plus de 100 millions de clients dans le monde', 'AXA recherche des alternants en BTS assurance, licence banque-assurance ou bachelor gestion de patrimoine. Profils rigoureux, avec un intérêt fort pour le conseil patrimonial.', ARRAY['Qu''est-ce qui vous attire dans le conseil en prévoyance et gestion de patrimoine chez AXA ?','Comment expliquez-vous l''importance de la prévoyance à un client jeune qui ne l''a pas anticipée ?','Décrivez votre approche pour construire une relation de confiance sur le long terme avec un client.','Comment gérez-vous la responsabilité de conseiller quelqu''un sur des décisions patrimoniales importantes ?','Quelle est votre vision des enjeux de la retraite et de la transmission de patrimoine en France ?'], ARRAY['Quelles sont les différences entre assurance vie, plan d''épargne retraite (PER) et autres produits d''épargne à long terme ?','Comment réaliser un bilan patrimonial complet pour un client cadre avec famille et bien immobilier ?','Quels sont les avantages fiscaux de l''assurance vie en France et comment les expliquer à un client ?','Qu''est-ce que la clause bénéficiaire d''une assurance vie et pourquoi est-elle si importante ?'], '50.png', FALSE),
(51, 'AGENCE AXA David Blanc', 'Agence AXA David Blanc', 'BANQUE / ASSURANCE', 'Thomas Gros', 'BLANC DAVID', 'https://www.axa.fr', 'axa.fr', 'Agence d''assurance généraliste', 'Votre conseiller AXA de proximité', '', '', 'L''agence AXA de David Blanc est une agence d''assurance généraliste proposant l''ensemble des solutions AXA aux particuliers et aux professionnels : auto, habitation, santé, prévoyance et placements. En tant qu''agent général AXA, David Blanc accompagne ses clients avec un service personnalisé et de proximité. Les alternants y développent une vue d''ensemble complète de tous les produits d''assurance.', 'L''agence AXA David Blanc s''est développée en construisant un portefeuille de clients fidèles grâce à un service de qualité et une présence de proximité. Agent général exclusif AXA, David Blanc bénéficie de la force et de la notoriété du premier groupe d''assurance européen tout en conservant son autonomie entrepreneuriale. L''agence est reconnue localement pour son conseil personnalisé et sa réactivité face aux besoins de ses clients.', ARRAY['Proximité','Confiance','Conseil','Réactivité','Engagement'], ARRAY['Conseiller les clients particuliers et professionnels sur leurs besoins d''assurance','Gérer les contrats et assurer le suivi des sinistres','Développer le portefeuille clients par la prospection et les recommandations','Assurer un service de qualité au quotidien en agence'], ARRAY['Agents généraux d''autres compagnies (Allianz, Generali)','courtiers locaux','assureurs en ligne'], 'Agence généraliste AXA, portefeuille clients diversifié (auto, habitation, santé, vie), service personnalisé', 'L''agence recherche des alternants en BTS assurance ou licence banque-assurance. Profils relationnels, organisés et intéressés par les métiers du conseil en assurance.', ARRAY['Pourquoi souhaitez-vous découvrir le métier d''agent général d''assurance plutôt que de travailler en compagnie ?','Comment gérez-vous un portefeuille de clients très diversifiés avec des besoins très différents ?','Décrivez comment vous expliquez simplement un contrat d''assurance à un client non spécialiste.','Comment réagissez-vous face à un client qui conteste le refus d''indemnisation de son sinistre ?','Quelle est votre conception de la fidélité client dans une agence d''assurance de proximité ?'], ARRAY['Quelles sont les garanties essentielles d''un contrat d''assurance multirisque habitation ?','Comment analyser le besoin d''un client en assurance auto pour lui proposer le niveau de garanties adapté ?','Qu''est-ce que la convention IRSA et comment s''applique-t-elle dans la gestion des sinistres auto ?','Comment gérer efficacement un sinistre habitation (dégât des eaux, vol) de l''ouverture à l''indemnisation ?'], '51.png', FALSE),
(52, 'MUTUELLE DE POITIERS ASSURANCES VIOLLEAU BERKANI', 'Mutuelle de Poitiers', 'BANQUE / ASSURANCE', 'Thomas Gros', 'BERKANI SONIA', 'https://www.mutuelledepoitiers.fr', 'mutuelledepoitiers.fr', 'Assurance mutualiste', 'Une assurance à taille humaine, au service de ses membres', '', '', 'La Mutuelle de Poitiers Assurances est une compagnie d''assurance mutualiste proposant des solutions d''assurance pour les particuliers (auto, habitation, santé) et les professionnels. L''agence Violleau Berkani représente la mutuelle localement avec un service de proximité et personnalisé. Les alternants y découvrent les valeurs du mutualisme appliquées à l''assurance.', 'La Mutuelle de Poitiers Assurances a été fondée en 1844 à Poitiers et a su traverser plus de 180 ans d''histoire en restant fidèle à ses valeurs mutualistes. Comme toute mutuelle, elle n''a pas d''actionnaires et ses bénéfices sont réinvestis au profit de ses membres. Son réseau d''agents généraux comme l''agence Violleau Berkani assure une présence de terrain et un accompagnement personnalisé dans les territoires.', ARRAY['Solidarité mutualiste','Proximité','Confiance','Transparence','Engagement'], ARRAY['Conseiller les clients sur les produits d''assurance de la mutuelle','Gérer les contrats et accompagner les clients en cas de sinistre','Développer le portefeuille de membres de l''agence','Assurer un service de qualité ancré dans les valeurs mutualistes'], ARRAY['Groupama','Macif','Maif','Matmut','Société Générale Assurances'], 'Fondée en 1844, plus de 180 ans d''existence, modèle mutualiste sans actionnaires, réseau d''agences en France', 'La Mutuelle de Poitiers recherche des alternants en BTS assurance ou licence banque-assurance. Profils sensibles aux valeurs mutualistes, rigoureux et ayant le sens du service.', ARRAY['Qu''est-ce que le modèle mutualiste représente pour vous et en quoi vous y adhérez ?','Comment expliquez-vous la différence entre une mutuelle d''assurance et une compagnie d''assurance commerciale ?','Décrivez comment vous établissez une relation de confiance avec un nouveau client d''assurance.','Comment gérez-vous un client dont le sinistre n''est pas couvert par son contrat ?','Quelle est l''importance de l''ancrage local dans les valeurs d''une mutuelle d''assurance ?'], ARRAY['Quels sont les avantages du modèle mutualiste pour les assurés par rapport aux assureurs commerciaux ?','Comment réaliser un audit des besoins d''assurance d''un ménage pour lui proposer une couverture globale ?','Quelles sont les principales exclusions de garantie à connaître en assurance auto et habitation ?','Comment se déroule la procédure d''indemnisation d''un sinistre habitation causé par une catastrophe naturelle ?'], '52.png', FALSE),
(53, 'Askovet', 'Askovet', 'Solution digitale', '', 'Jurquet Laura', 'https://www.askovet.fr', 'askovet.com', 'Services vétérinaires et bien-être animal', 'La santé animale, notre passion', '', '', 'Askovet est une structure dédiée aux services vétérinaires et au bien-être animal, proposant des solutions d''accompagnement pour les propriétaires d''animaux de compagnie. L''entreprise allie expertise vétérinaire et sensibilité au bien-être animal pour offrir des services de qualité. Les alternants y découvrent un secteur porteur combinant commerce, services et passion pour les animaux.', 'Askovet a été fondée par Laura Jurquet avec la passion du bien-être animal et la volonté de proposer des services innovants aux propriétaires d''animaux de compagnie. En combinant conseil, accompagnement et services pratiques, Askovet s''est développée comme une ressource de confiance pour les amoureux des animaux. L''entreprise continue de se développer dans un secteur en forte croissance, porté par l''humanisation croissante des animaux de compagnie.', ARRAY['Passion animale','Bienveillance','Expertise','Engagement','Innovation'], ARRAY['Conseiller les propriétaires d''animaux sur la santé et le bien-être de leurs compagnons','Développer les services et l''offre commerciale de la structure','Gérer les relations clients et assurer leur satisfaction','Contribuer à la communication et au marketing de l''entreprise'], ARRAY['Cliniques vétérinaires locales','Pets & Co','Animalis','Maxi Zoo','plateformes de conseil vétérinaire en ligne'], 'Secteur des animaux de compagnie en forte croissance (plus de 5 milliards d''euros en France), humanisation croissante des animaux', 'Askovet recherche des alternants en BTS commerce, communication ou marketing. Profils passionnés par les animaux, avec le sens du service et la curiosité pour un secteur innovant.', ARRAY['Qu''est-ce qui vous attire dans le secteur des services dédiés aux animaux de compagnie ?','Comment votre passion personnelle pour les animaux peut-elle être un atout professionnel ?','Décrivez une situation où vous avez dû convaincre quelqu''un de prendre une décision dans l''intérêt de son animal.','Comment gérez-vous la relation avec un propriétaire très anxieux concernant la santé de son animal ?','Comment vous informez-vous des évolutions du marché des services vétérinaires et du bien-être animal ?'], ARRAY['Quelles sont les tendances actuelles du marché des animaux de compagnie (alimentation premium, médecine préventive, assurance animale) ?','Comment développer une stratégie de communication digitale pour toucher les propriétaires d''animaux ?','Comment fidéliser une clientèle de propriétaires d''animaux de compagnie grâce à un programme de services ?','Quels sont les aspects réglementaires à connaître dans le secteur des services vétérinaires (encadrement professionnel, actes vétérinaires) ?'], '53.png', FALSE),
(54, 'COLDWELL BANKER', 'COLDWELL BANKER', 'IMMOBILIER', '', '', 'https://www.coldwellbanker.fr/', '', 'Immobilier', '', '', '', '', '', '{}', '{}', '{}', '', '', '{}', '{}', NULL, TRUE)
